"use client";
import { useState, useEffect } from 'react';
import { useSession } from 'next-auth/react';
import { useRouter } from 'next/navigation';
import styles from '../page.module.css';

interface AnalyticsData {
    userGrowth: { date: string; count: number }[];
    challengeStats: { status: string; count: number }[];
    submissionTrend: { date: string; count: number }[];
    topCategories: { category: string; count: number }[];
    totalUsers: number;
    totalSubmissions: number;
}

export default function AdminAnalyticsPage() {
    const { data: session, status } = useSession();
    const router = useRouter();
    const [loading, setLoading] = useState(true);
    const [analytics, setAnalytics] = useState<AnalyticsData | null>(null);

    useEffect(() => {
        if (status === 'unauthenticated') {
            router.push('/auth/login');
        } else if (status === 'authenticated' && session?.user?.role !== 'admin') {
            router.push('/');
        } else if (status === 'authenticated') {
            fetchAnalytics();
            // Poll every 10 seconds for "realtime" feel
            const interval = setInterval(fetchAnalytics, 10000);
            return () => clearInterval(interval);
        }
    }, [status, session, router]);

    const fetchAnalytics = async () => {
        try {
            if (!analytics) setLoading(true);
            const [usersRes, challengesRes, submissionsRes] = await Promise.all([
                fetch('/api/admin/stats'),
                fetch('/api/challenges?limit=100'),
                fetch('/api/submissions?limit=100'),
            ]);

            const [statsData, challengesData, submissionsData] = await Promise.all([
                usersRes.json(),
                challengesRes.json(),
                submissionsRes.json(),
            ]);

            const challengeStats = [
                { status: 'Active', count: challengesData.challenges?.filter((c: any) => c.status === 'active').length || 0 },
                { status: 'Upcoming', count: challengesData.challenges?.filter((c: any) => c.status === 'upcoming').length || 0 },
                { status: 'Ended', count: challengesData.challenges?.filter((c: any) => c.status === 'ended').length || 0 },
            ];

            const categoryCount: Record<string, number> = {};
            challengesData.challenges?.forEach((c: any) => {
                categoryCount[c.category] = (categoryCount[c.category] || 0) + 1;
            });

            const topCategories = Object.entries(categoryCount)
                .map(([category, count]) => ({ category, count: count as number }))
                .sort((a, b) => b.count - a.count)
                .slice(0, 5);

            setAnalytics({
                userGrowth: [],
                challengeStats,
                submissionTrend: [],
                topCategories,
                totalUsers: statsData.stats?.totalUsers || 0,
                totalSubmissions: statsData.stats?.totalSubmissions || 0,
            });
        } catch (error) {
            console.error('Error fetching analytics:', error);
        } finally {
            setLoading(false);
        }
    };

    if (loading || status === 'loading') {
        return (
            <div className={styles.adminDashboard}>
                <div style={{ padding: '2rem', textAlign: 'center' }}>
                    <div className="spinner"></div>
                    <p style={{ marginTop: '1rem', color: 'var(--text-secondary)' }}>Loading analytics...</p>
                </div>
            </div>
        );
    }

    const totalChallenges = analytics?.challengeStats.reduce((acc, curr) => acc + curr.count, 0) || 0;
    const activeChallenges = analytics?.challengeStats.find(s => s.status === 'Active')?.count || 0;
    const engagementRate = analytics?.totalUsers ? Math.round((analytics.totalSubmissions / analytics.totalUsers) * 10) / 10 : 0;

    return (
        <div className={styles.adminDashboard}>
            <header className={styles.header}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <div>
                        <h1 className="text-gradient">Platform Analytics</h1>
                        <p style={{ color: 'var(--text-secondary)', marginTop: '0.4rem' }}>
                            Real-time performance metrics and insights
                        </p>
                    </div>
                    <div style={{
                        padding: '0.5rem 1rem',
                        background: 'rgba(16, 185, 129, 0.1)',
                        border: '1px solid rgba(16, 185, 129, 0.2)',
                        borderRadius: '20px',
                        display: 'flex',
                        alignItems: 'center',
                        gap: '0.5rem'
                    }}>
                        <span style={{
                            width: '8px',
                            height: '8px',
                            background: '#10b981',
                            borderRadius: '50%',
                            boxShadow: '0 0 10px #10b981'
                        }}></span>
                        <span style={{ color: '#10b981', fontSize: '0.85rem', fontWeight: 600 }}>Live Data</span>
                    </div>
                </div>
            </header>

            {/* Key Metrics Grid */}
            <div style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(4, 1fr)',
                gap: '1.5rem',
                marginBottom: '2rem'
            }}>
                {[
                    { label: 'Total Users', value: analytics?.totalUsers, change: '+12%', color: '#6366f1', icon: '≡ƒæÑ' },
                    { label: 'Total Submissions', value: analytics?.totalSubmissions, change: '+5%', color: '#ec4899', icon: '≡ƒô╕' },
                    { label: 'Active Challenges', value: activeChallenges, change: 'Now', color: '#10b981', icon: '≡ƒöÑ' },
                    { label: 'Avg. Engagement', value: engagementRate, suffix: ' subs/user', color: '#f59e0b', icon: '≡ƒôè' }
                ].map((stat, idx) => (
                    <div key={idx} className="glass-card-hover" style={{
                        padding: '1.5rem',
                        display: 'flex',
                        flexDirection: 'column',
                        gap: '0.5rem',
                        position: 'relative',
                        overflow: 'hidden'
                    }}>
                        <div style={{
                            position: 'absolute',
                            top: 0,
                            right: 0,
                            padding: '1rem',
                            opacity: 0.1,
                            fontSize: '3rem',
                            filter: 'grayscale(100%)'
                        }}>
                            {stat.icon}
                        </div>
                        <span style={{ color: '#94a3b8', fontSize: '0.9rem', fontWeight: 500 }}>{stat.label}</span>
                        <div style={{ display: 'flex', alignItems: 'baseline', gap: '0.5rem' }}>
                            <h2 style={{ fontSize: '2rem', fontWeight: 700, color: 'white' }}>
                                {stat.value?.toLocaleString() || 0}
                            </h2>
                            {stat.suffix && <span style={{ fontSize: '0.9rem', color: '#94a3b8' }}>{stat.suffix}</span>}
                        </div>
                        <div style={{
                            display: 'inline-flex',
                            alignItems: 'center',
                            gap: '0.25rem',
                            fontSize: '0.8rem',
                            color: stat.color,
                            background: `${stat.color}15`,
                            padding: '0.25rem 0.5rem',
                            borderRadius: '12px',
                            width: 'fit-content'
                        }}>
                            <span>{stat.change?.includes('+') ? 'Γåù' : 'ΓÇó'}</span>
                            {stat.change || '0%'}
                        </div>
                    </div>
                ))}
            </div>

            <div style={{ display: 'grid', gridTemplateColumns: '2fr 1fr', gap: '1.5rem' }}>

                {/* Main Content - Categories Chart */}
                <div className="glass-card" style={{ padding: '2rem' }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '2rem' }}>
                        <h3 style={{ fontSize: '1.1rem' }}>≡ƒÅå Top Performing Categories</h3>
                        <button style={{
                            background: 'rgba(255,255,255,0.05)',
                            border: 'none',
                            color: '#94a3b8',
                            padding: '0.25rem 0.75rem',
                            borderRadius: '6px',
                            fontSize: '0.8rem',
                            cursor: 'pointer'
                        }}>Last 30 Days</button>
                    </div>

                    <div style={{ display: 'flex', flexDirection: 'column', gap: '1.25rem' }}>
                        {analytics?.topCategories.map((cat, idx) => {
                            const maxVal = analytics.topCategories[0]?.count || 1;
                            const percentage = (cat.count / maxVal) * 100;

                            return (
                                <div key={idx} style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                                    <div style={{ width: '120px', fontWeight: 500, color: '#e2e8f0' }}>{cat.category}</div>
                                    <div style={{ flex: 1, height: '8px', background: 'rgba(255,255,255,0.05)', borderRadius: '4px', overflow: 'hidden' }}>
                                        <div style={{
                                            width: `${percentage}%`,
                                            height: '100%',
                                            background: `linear-gradient(90deg, #6366f1 0%, #a855f7 100%)`,
                                            borderRadius: '4px',
                                            transition: 'width 1s ease-out'
                                        }} />
                                    </div>
                                    <div style={{ width: '40px', textAlign: 'right', fontWeight: 600, color: 'white' }}>{cat.count}</div>
                                </div>
                            );
                        })}
                    </div>
                </div>

                {/* Side Content - Challenge Status */}
                <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
                    <div className="glass-card" style={{ padding: '2rem', flex: 1 }}>
                        <h3 style={{ marginBottom: '1.5rem', fontSize: '1.1rem' }}>≡ƒôè Challenge Status</h3>

                        <div style={{
                            display: 'flex',
                            justifyContent: 'center',
                            alignItems: 'center',
                            height: '200px',
                            position: 'relative'
                        }}>
                            {/* Simple CSS Donut Chart Visualization */}
                            <div style={{
                                width: '160px',
                                height: '160px',
                                borderRadius: '50%',
                                background: `conic-gradient(
                                    #10b981 0% ${(activeChallenges / totalChallenges) * 100}%, 
                                    #f59e0b 0% ${((activeChallenges + (analytics?.challengeStats.find(s => s.status === 'Upcoming')?.count || 0)) / totalChallenges) * 100}%, 
                                    #64748b 0% 100%
                                )`,
                                position: 'relative',
                                display: 'flex',
                                alignItems: 'center',
                                justifyContent: 'center'
                            }}>
                                <div style={{
                                    width: '120px',
                                    height: '120px',
                                    background: '#09090b', // match card bg
                                    borderRadius: '50%',
                                    display: 'flex',
                                    flexDirection: 'column',
                                    alignItems: 'center',
                                    justifyContent: 'center'
                                }}>
                                    <span style={{ fontSize: '2rem', fontWeight: 700, color: 'white' }}>{totalChallenges}</span>
                                    <span style={{ fontSize: '0.8rem', color: '#94a3b8' }}>Total</span>
                                </div>
                            </div>
                        </div>

                        <div style={{ display: 'flex', justifyContent: 'center', gap: '1.5rem', marginTop: '1.5rem' }}>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                                <span style={{ width: '10px', height: '10px', borderRadius: '2px', background: '#10b981' }}></span>
                                <span style={{ fontSize: '0.85rem', color: '#cbd5e1' }}>Active</span>
                            </div>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                                <span style={{ width: '10px', height: '10px', borderRadius: '2px', background: '#f59e0b' }}></span>
                                <span style={{ fontSize: '0.85rem', color: '#cbd5e1' }}>Upcoming</span>
                            </div>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                                <span style={{ width: '10px', height: '10px', borderRadius: '2px', background: '#64748b' }}></span>
                                <span style={{ fontSize: '0.85rem', color: '#cbd5e1' }}>Ended</span>
                            </div>
                        </div>
                    </div>
                </div>

            </div>
        </div>
    );
}

"use client";
import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { useSession } from 'next-auth/react';
import styles from '../../page.module.css';

export default function CreateChallengePage() {
    const router = useRouter();
    const { data: session } = useSession();
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');

    const [formData, setFormData] = useState({
        title: '',
        description: '',
        category: 'Creative',
        startDate: '',
        endDate: '',
        image: '',
        badge: 'Normal',
        prizeAmount: '',
        prizeDescription: '',
    });

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
        const { name, value } = e.target;
        setFormData(prev => ({ ...prev, [name]: value }));
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setError('');

        try {
            const payload = {
                ...formData,
                prize: formData.badge === 'Prize' ? {
                    amount: Number(formData.prizeAmount),
                    description: formData.prizeDescription
                } : undefined
            };

            const res = await fetch('/api/challenges', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(payload),
            });

            const data = await res.json();

            if (res.ok) {
                router.push('/admin/challenges');
                router.refresh();
            } else {
                setError(data.error || 'Failed to create challenge');
            }
        } catch (err) {
            setError('An error occurred. Please try again.');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className={styles.adminDashboard}>
            <header className={styles.header}>
                <h1 className="text-gradient">Create New Challenge</h1>
                <button className="btn-secondary" onClick={() => router.back()}>Cancel</button>
            </header>

            <div className="glass-card" style={{ padding: '2rem', maxWidth: '800px', margin: '0 auto' }}>
                {error && (
                    <div style={{
                        padding: '1rem',
                        background: 'rgba(239, 68, 68, 0.2)',
                        border: '1px solid #ef4444',
                        borderRadius: '8px',
                        marginBottom: '1.5rem',
                        color: '#fca5a5'
                    }}>
                        {error}
                    </div>
                )}

                <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
                    <div className={styles.formGroup}>
                        <label>Challenge Title</label>
                        <input
                            type="text"
                            name="title"
                            value={formData.title}
                            onChange={handleChange}
                            placeholder="e.g. Sunset Photography"
                            required
                            className={styles.input}
                            style={{ width: '100%', padding: '0.75rem', borderRadius: '8px', background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.1)', color: 'white' }}
                        />
                    </div>

                    <div className={styles.formGroup}>
                        <label>Description</label>
                        <textarea
                            name="description"
                            value={formData.description}
                            onChange={handleChange}
                            placeholder="Describe the challenge rules and goals..."
                            required
                            rows={5}
                            style={{ width: '100%', padding: '0.75rem', borderRadius: '8px', background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.1)', color: 'white' }}
                        />
                    </div>

                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1.5rem' }}>
                        <div className={styles.formGroup}>
                            <label>Category</label>
                            <select
                                name="category"
                                value={formData.category}
                                onChange={handleChange}
                                style={{ width: '100%', padding: '0.75rem', borderRadius: '8px', background: '#1a1a1a', border: '1px solid rgba(255,255,255,0.1)', color: 'white' }}
                            >
                                <option value="Creative">Creative</option>
                                <option value="Fitness">Fitness</option>
                                <option value="Learning">Learning</option>
                                <option value="Lifestyle">Lifestyle</option>
                                <option value="Other">Other</option>
                            </select>
                        </div>

                        <div className={styles.formGroup}>
                            <label>Badge Type</label>
                            <select
                                name="badge"
                                value={formData.badge}
                                onChange={handleChange}
                                style={{ width: '100%', padding: '0.75rem', borderRadius: '8px', background: '#1a1a1a', border: '1px solid rgba(255,255,255,0.1)', color: 'white' }}
                            >
                                <option value="Normal">Normal</option>
                                <option value="Prize">Prize (Money/Reward)</option>
                            </select>
                        </div>
                    </div>

                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1.5rem' }}>
                        <div className={styles.formGroup}>
                            <label>Start Date</label>
                            <input
                                type="datetime-local"
                                name="startDate"
                                value={formData.startDate}
                                onChange={handleChange}
                                required
                                style={{ width: '100%', padding: '0.75rem', borderRadius: '8px', background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.1)', color: 'white' }}
                            />
                        </div>

                        <div className={styles.formGroup}>
                            <label>End Date</label>
                            <input
                                type="datetime-local"
                                name="endDate"
                                value={formData.endDate}
                                onChange={handleChange}
                                required
                                style={{ width: '100%', padding: '0.75rem', borderRadius: '8px', background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.1)', color: 'white' }}
                            />
                        </div>
                    </div>

                    <div className={styles.formGroup}>
                        <label>Cover Image URL</label>
                        <input
                            type="url"
                            name="image"
                            value={formData.image}
                            onChange={handleChange}
                            placeholder="https://example.com/image.jpg"
                            required
                            style={{ width: '100%', padding: '0.75rem', borderRadius: '8px', background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.1)', color: 'white' }}
                        />
                    </div>

                    {formData.badge === 'Prize' && (
                        <div style={{ padding: '1rem', background: 'rgba(255,215,0,0.1)', borderRadius: '8px', border: '1px solid rgba(255,215,0,0.3)' }}>
                            <h4 style={{ color: '#fbbf24', marginBottom: '1rem' }}>Prize Details</h4>
                            <div style={{ display: 'grid', gridTemplateColumns: '1fr 2fr', gap: '1rem' }}>
                                <div>
                                    <label>Amount ($)</label>
                                    <input
                                        type="number"
                                        name="prizeAmount"
                                        value={formData.prizeAmount}
                                        onChange={handleChange}
                                        placeholder="100"
                                        style={{ width: '100%', padding: '0.5rem', borderRadius: '4px', background: 'rgba(0,0,0,0.3)', border: '1px solid rgba(255,255,255,0.1)', color: 'white' }}
                                    />
                                </div>
                                <div>
                                    <label>Prize Description</label>
                                    <input
                                        type="text"
                                        name="prizeDescription"
                                        value={formData.prizeDescription}
                                        onChange={handleChange}
                                        placeholder="Amazon Gift Card"
                                        style={{ width: '100%', padding: '0.5rem', borderRadius: '4px', background: 'rgba(0,0,0,0.3)', border: '1px solid rgba(255,255,255,0.1)', color: 'white' }}
                                    />
                                </div>
                            </div>
                        </div>
                    )}

                    <div style={{ display: 'flex', justifyContent: 'flex-end', gap: '1rem', marginTop: '1rem' }}>
                        <button
                            type="button"
                            onClick={() => router.back()}
                            className={styles.btnSecondary}
                            style={{ padding: '0.75rem 1.5rem', borderRadius: '8px', background: 'transparent', border: '1px solid rgba(255,255,255,0.2)', color: 'white', cursor: 'pointer' }}
                        >
                            Cancel
                        </button>
                        <button
                            type="submit"
                            disabled={loading}
                            className="btn-primary"
                            style={{ padding: '0.75rem 2rem', borderRadius: '8px', background: 'var(--gradient-main)', border: 'none', color: 'white', fontWeight: 600, cursor: 'pointer', opacity: loading ? 0.7 : 1 }}
                        >
                            {loading ? 'Creating...' : 'Create Challenge'}
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
}

"use client";
import { useState, useEffect, use } from 'react';
import { useRouter } from 'next/navigation';
import { useSession } from 'next-auth/react';
import styles from '../../../page.module.css';

interface CreateEditDate {
    params: Promise<{ id: string }>;
}

export default function EditChallengePage(props: CreateEditDate) {
    const params = use(props.params);
    const router = useRouter();
    const { data: session } = useSession();
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);
    const [error, setError] = useState('');

    const [formData, setFormData] = useState({
        title: '',
        description: '',
        category: 'Creative',
        startDate: '',
        endDate: '',
        image: '',
        badge: 'Normal',
        prizeAmount: '',
        prizeDescription: '',
    });

    useEffect(() => {
        fetchChallenge();
    }, [params.id]);

    const fetchChallenge = async () => {
        try {
            const res = await fetch(`/api/challenges/${params.id}`);
            const data = await res.json();

            if (res.ok && data.challenge) {
                const c = data.challenge;
                setFormData({
                    title: c.title,
                    description: c.description,
                    category: c.category,
                    startDate: new Date(c.startDate).toISOString().slice(0, 16),
                    endDate: new Date(c.endDate).toISOString().slice(0, 16),
                    image: c.image,
                    badge: c.badge,
                    prizeAmount: c.prize?.amount?.toString() || '',
                    prizeDescription: c.prize?.description || '',
                });
            } else {
                setError('Failed to load challenge details');
            }
        } catch (err) {
            setError('Error loading challenge');
        } finally {
            setLoading(false);
        }
    };

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
        const { name, value } = e.target;
        setFormData(prev => ({ ...prev, [name]: value }));
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setSaving(true);
        setError('');

        try {
            const payload = {
                ...formData,
                prize: formData.badge === 'Prize' ? {
                    amount: Number(formData.prizeAmount),
                    description: formData.prizeDescription
                } : undefined
            };

            const res = await fetch(`/api/challenges/${params.id}`, {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(payload),
            });

            const data = await res.json();

            if (res.ok) {
                router.push('/admin/challenges');
                router.refresh();
            } else {
                setError(data.error || 'Failed to update challenge');
            }
        } catch (err) {
            setError('An error occurred. Please try again.');
        } finally {
            setSaving(false);
        }
    };

    if (loading) return <div className="spinner" style={{ margin: '5rem auto' }}></div>;

    return (
        <div className={styles.adminDashboard}>
            <header className={styles.header}>
                <h1 className="text-gradient">Edit Challenge</h1>
                <button className="btn-secondary" onClick={() => router.back()}>Cancel</button>
            </header>

            <div className="glass-card" style={{ padding: '2rem', maxWidth: '800px', margin: '0 auto' }}>
                {error && (
                    <div style={{
                        padding: '1rem',
                        background: 'rgba(239, 68, 68, 0.2)',
                        border: '1px solid #ef4444',
                        borderRadius: '8px',
                        marginBottom: '1.5rem',
                        color: '#fca5a5'
                    }}>
                        {error}
                    </div>
                )}

                <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
                    <div className={styles.formGroup}>
                        <label>Challenge Title</label>
                        <input
                            type="text"
                            name="title"
                            value={formData.title}
                            onChange={handleChange}
                            required
                            style={{ width: '100%', padding: '0.75rem', borderRadius: '8px', background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.1)', color: 'white' }}
                        />
                    </div>

                    <div className={styles.formGroup}>
                        <label>Description</label>
                        <textarea
                            name="description"
                            value={formData.description}
                            onChange={handleChange}
                            required
                            rows={5}
                            style={{ width: '100%', padding: '0.75rem', borderRadius: '8px', background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.1)', color: 'white' }}
                        />
                    </div>

                    {/* Same fields as Create... reused */}
                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1.5rem' }}>
                        <div className={styles.formGroup}>
                            <label>Category</label>
                            <select
                                name="category"
                                value={formData.category}
                                onChange={handleChange}
                                style={{ width: '100%', padding: '0.75rem', borderRadius: '8px', background: '#1a1a1a', border: '1px solid rgba(255,255,255,0.1)', color: 'white' }}
                            >
                                <option value="Creative">Creative</option>
                                <option value="Fitness">Fitness</option>
                                <option value="Learning">Learning</option>
                                <option value="Lifestyle">Lifestyle</option>
                                <option value="Other">Other</option>
                            </select>
                        </div>

                        <div className={styles.formGroup}>
                            <label>Badge Type</label>
                            <select
                                name="badge"
                                value={formData.badge}
                                onChange={handleChange}
                                style={{ width: '100%', padding: '0.75rem', borderRadius: '8px', background: '#1a1a1a', border: '1px solid rgba(255,255,255,0.1)', color: 'white' }}
                            >
                                <option value="Normal">Normal</option>
                                <option value="Prize">Prize (Money/Reward)</option>
                            </select>
                        </div>
                    </div>

                    <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1.5rem' }}>
                        <div className={styles.formGroup}>
                            <label>Start Date</label>
                            <input
                                type="datetime-local"
                                name="startDate"
                                value={formData.startDate}
                                onChange={handleChange}
                                required
                                style={{ width: '100%', padding: '0.75rem', borderRadius: '8px', background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.1)', color: 'white' }}
                            />
                        </div>

                        <div className={styles.formGroup}>
                            <label>End Date</label>
                            <input
                                type="datetime-local"
                                name="endDate"
                                value={formData.endDate}
                                onChange={handleChange}
                                required
                                style={{ width: '100%', padding: '0.75rem', borderRadius: '8px', background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.1)', color: 'white' }}
                            />
                        </div>
                    </div>

                    <div className={styles.formGroup}>
                        <label>Cover Image URL</label>
                        <input
                            type="url"
                            name="image"
                            value={formData.image}
                            onChange={handleChange}
                            required
                            style={{ width: '100%', padding: '0.75rem', borderRadius: '8px', background: 'rgba(255,255,255,0.05)', border: '1px solid rgba(255,255,255,0.1)', color: 'white' }}
                        />
                    </div>

                    {formData.badge === 'Prize' && (
                        <div style={{ padding: '1rem', background: 'rgba(255,215,0,0.1)', borderRadius: '8px', border: '1px solid rgba(255,215,0,0.3)' }}>
                            <h4 style={{ color: '#fbbf24', marginBottom: '1rem' }}>Prize Details</h4>
                            <div style={{ display: 'grid', gridTemplateColumns: '1fr 2fr', gap: '1rem' }}>
                                <div>
                                    <label>Amount ($)</label>
                                    <input
                                        type="number"
                                        name="prizeAmount"
                                        value={formData.prizeAmount}
                                        onChange={handleChange}
                                        style={{ width: '100%', padding: '0.5rem', borderRadius: '4px', background: 'rgba(0,0,0,0.3)', border: '1px solid rgba(255,255,255,0.1)', color: 'white' }}
                                    />
                                </div>
                                <div>
                                    <label>Prize Description</label>
                                    <input
                                        type="text"
                                        name="prizeDescription"
                                        value={formData.prizeDescription}
                                        onChange={handleChange}
                                        style={{ width: '100%', padding: '0.5rem', borderRadius: '4px', background: 'rgba(0,0,0,0.3)', border: '1px solid rgba(255,255,255,0.1)', color: 'white' }}
                                    />
                                </div>
                            </div>
                        </div>
                    )}

                    <div style={{ display: 'flex', justifyContent: 'flex-end', gap: '1rem', marginTop: '1rem' }}>
                        <button
                            type="button"
                            onClick={() => router.back()}
                            className={styles.btnSecondary}
                            style={{ padding: '0.75rem 1.5rem', borderRadius: '8px', background: 'transparent', border: '1px solid rgba(255,255,255,0.2)', color: 'white', cursor: 'pointer' }}
                        >
                            Cancel
                        </button>
                        <button
                            type="submit"
                            disabled={saving}
                            className="btn-primary"
                            style={{ padding: '0.75rem 2rem', borderRadius: '8px', background: 'var(--gradient-main)', border: 'none', color: 'white', fontWeight: 600, cursor: 'pointer', opacity: saving ? 0.7 : 1 }}
                        >
                            {saving ? 'Saving...' : 'Update Challenge'}
                        </button>
                    </div>
                </form>
            </div>
        </div>
    );
}

"use client";
import { useState, useEffect } from 'react';
import styles from '../page.module.css';

interface Collection {
    name: string;
    count: number;
}

const ICONS: Record<string, string> = {
    users: '≡ƒæñ',
    challenges: 'ΓÜö∩╕Å',
    submissions: '≡ƒô╖',
    votes: 'Γ¥ñ∩╕Å',
    comments: '≡ƒÆ¼',
    notifications: '≡ƒöö',
    default: '≡ƒôä'
};

export default function DatabasePage() {
    const [collections, setCollections] = useState<Collection[]>([]);
    const [selectedCollection, setSelectedCollection] = useState<string | null>(null);
    const [documents, setDocuments] = useState<any[]>([]);
    const [filteredDocuments, setFilteredDocuments] = useState<any[]>([]);
    const [searchQuery, setSearchQuery] = useState('');
    const [selectedDoc, setSelectedDoc] = useState<any | null>(null);
    const [jsonInput, setJsonInput] = useState('');
    const [loading, setLoading] = useState(false);
    const [status, setStatus] = useState('');

    useEffect(() => {
        fetchCollections();
    }, []);

    useEffect(() => {
        if (selectedCollection) {
            fetchDocuments(selectedCollection);
        }
    }, [selectedCollection]);

    useEffect(() => {
        if (searchQuery) {
            const lower = searchQuery.toLowerCase();
            const filtered = documents.filter(doc =>
                JSON.stringify(doc).toLowerCase().includes(lower)
            );
            setFilteredDocuments(filtered);
        } else {
            setFilteredDocuments(documents);
        }
    }, [searchQuery, documents]);

    useEffect(() => {
        if (selectedDoc) {
            setJsonInput(JSON.stringify(selectedDoc, null, 2));
        } else {
            setJsonInput('');
        }
    }, [selectedDoc]);

    const fetchCollections = async () => {
        try {
            const res = await fetch('/api/admin/database');
            const data = await res.json();
            if (res.ok) setCollections(data.collections);
        } catch (e) {
            console.error(e);
        }
    };

    const fetchDocuments = async (colName: string) => {
        setLoading(true);
        try {
            const res = await fetch(`/api/admin/database?collection=${colName}&limit=100`);
            const data = await res.json();
            if (res.ok) {
                setDocuments(data.documents);
                setFilteredDocuments(data.documents);
                setSelectedDoc(null);
            }
        } catch (e) {
            console.error(e);
        } finally {
            setLoading(false);
        }
    };

    const handleSave = async () => {
        if (!selectedDoc || !selectedCollection) return;

        try {
            const parsedData = JSON.parse(jsonInput);
            setStatus('Saving...');

            const res = await fetch('/api/admin/database', {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    collection: selectedCollection,
                    id: selectedDoc._id,
                    data: parsedData
                })
            });

            if (res.ok) {
                const refreshed = { ...parsedData, _id: selectedDoc._id };
                setSelectedDoc(refreshed);
                setDocuments(docs => docs.map(d => d._id === selectedDoc._id ? refreshed : d));
                setStatus('Γ£à Saved successfully!');
                setTimeout(() => setStatus(''), 2000);
            } else {
                const err = await res.json();
                setStatus('Γ¥î Error: ' + err.error);
            }
        } catch (e: any) {
            setStatus('Γ¥î Invalid JSON: ' + e.message);
        }
    };


    const handleDelete = async () => {
        if (!selectedDoc || !selectedCollection || !confirm('Are you sure you want to delete this document? THIS CANNOT BE UNDONE.')) return;

        try {
            const res = await fetch(`/api/admin/database?collection=${selectedCollection}&id=${selectedDoc._id}`, {
                method: 'DELETE'
            });

            if (res.ok) {
                setDocuments(docs => docs.filter(d => d._id !== selectedDoc._id));
                setSelectedDoc(null);
                setStatus('≡ƒùæ∩╕Å Deleted successfully');
            } else {
                setStatus('Γ¥î Delete failed');
            }
        } catch (e) {
            console.error(e);
        }
    };

    const formatJSON = () => {
        try {
            const parsed = JSON.parse(jsonInput);
            setJsonInput(JSON.stringify(parsed, null, 2));
        } catch (e) {
            alert("Invalid JSON data");
        }
    };

    // Helper to render a nice preview card
    const renderDocCard = (doc: any) => {
        const isSelected = selectedDoc?._id === doc._id;

        // Extract common fields for preview
        const img = doc.avatar || doc.image || doc.mediaUrl;
        const title = doc.name || doc.title || doc.email || doc.username || doc._id;
        const subtitle = doc.email || doc.status || doc.role || doc.category || (doc.createdAt ? new Date(doc.createdAt).toLocaleDateString() : '');
        const extra = doc.participants ? `${doc.participants} participants` : doc.votes ? `${doc.votes} votes` : '';

        return (
            <div
                key={doc._id}
                onClick={() => setSelectedDoc(doc)}
                className="glass-card-hover"
                style={{
                    padding: '0.75rem',
                    background: isSelected ? 'rgba(212, 175, 55, 0.2)' : 'rgba(255,255,255,0.03)',
                    border: isSelected ? '1px solid var(--accent-primary)' : '1px solid rgba(255,255,255,0.05)',
                    borderRadius: '8px',
                    cursor: 'pointer',
                    display: 'flex',
                    gap: '0.75rem',
                    alignItems: 'center',
                    transition: 'all 0.2s ease',
                    marginBottom: '0.5rem'
                }}
            >
                {/* Thumbnail if available */}
                {img && typeof img === 'string' && img.startsWith('http') && (
                    <div style={{ width: '40px', height: '40px', borderRadius: '6px', overflow: 'hidden', flexShrink: 0, border: '1px solid rgba(255,255,255,0.1)' }}>
                        <img src={img} alt="" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                    </div>
                )}

                <div style={{ flex: 1, overflow: 'hidden' }}>
                    <div style={{ fontWeight: 500, color: isSelected ? 'var(--accent-primary)' : '#e2e8f0', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
                        {title}
                    </div>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: '2px' }}>
                        <span style={{ fontSize: '0.75rem', color: '#94a3b8' }}>{subtitle}</span>
                        {extra && <span style={{ fontSize: '0.7rem', background: 'rgba(255,255,255,0.1)', padding: '1px 4px', borderRadius: '3px' }}>{extra}</span>}
                    </div>
                    <div style={{ fontSize: '0.7rem', color: '#64748b', fontFamily: 'monospace', marginTop: '2px' }}>
                        ID: {doc._id}
                    </div>
                </div>
            </div>
        );
    };

    return (
        <div className={styles.adminDashboard} style={{ height: 'calc(100vh - 40px)', overflow: 'hidden', display: 'flex', flexDirection: 'column' }}>
            <header className={styles.header} style={{ flexShrink: 0, marginBottom: '1rem', paddingBottom: '0' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <div>
                        <h1 className="text-gradient">Database Manager</h1>
                        <p style={{ color: 'var(--text-secondary)' }}>Directly manipulate database records</p>
                    </div>
                    <div style={{ padding: '0.5rem 1rem', background: 'rgba(212, 175, 55, 0.1)', borderRadius: '20px', border: '1px solid rgba(212, 175, 55, 0.2)' }}>
                        <span style={{ color: 'var(--accent-primary)', fontSize: '0.9rem' }}>≡ƒöæ Admin Access Authenticated</span>
                    </div>
                </div>
            </header>

            <div style={{ display: 'grid', gridTemplateColumns: '220px 350px 1fr', gap: '1rem', flex: 1, height: '100%', overflow: 'hidden', paddingBottom: '1rem' }}>

                {/* 1. Collection List */}
                <div className="glass-card" style={{ display: 'flex', flexDirection: 'column', overflow: 'hidden', background: 'linear-gradient(145deg, rgba(255,255,255,0.03) 0%, rgba(255,255,255,0.01) 100%)' }}>
                    <div style={{ padding: '1rem', borderBottom: '1px solid rgba(255,255,255,0.05)' }}>
                        <h3 style={{ fontSize: '0.75rem', textTransform: 'uppercase', letterSpacing: '1px', color: '#94a3b8' }}>Collections</h3>
                    </div>
                    <div style={{ overflowY: 'auto', padding: '0.5rem', flex: 1 }}>
                        {collections.map(col => (
                            <button
                                key={col.name}
                                onClick={() => setSelectedCollection(col.name)}
                                style={{
                                    width: '100%',
                                    textAlign: 'left',
                                    padding: '0.75rem 1rem',
                                    background: selectedCollection === col.name ? 'linear-gradient(90deg, rgba(212, 175, 55, 0.2) 0%, rgba(212, 175, 55, 0) 100%)' : 'transparent',
                                    borderLeft: selectedCollection === col.name ? '3px solid var(--accent-primary)' : '3px solid transparent',
                                    borderTop: 'none', borderRight: 'none', borderBottom: 'none',
                                    color: selectedCollection === col.name ? 'white' : '#cbd5e1',
                                    cursor: 'pointer',
                                    display: 'flex',
                                    justifyContent: 'space-between',
                                    alignItems: 'center',
                                    marginBottom: '2px',
                                    borderRadius: '0 6px 6px 0',
                                    transition: 'all 0.2s'
                                }}
                            >
                                <span style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                                    <span>{ICONS[col.name] || ICONS.default}</span>
                                    <span style={{ fontWeight: selectedCollection === col.name ? 600 : 400 }}>{col.name}</span>
                                </span>
                                <span style={{ fontSize: '0.75rem', background: 'rgba(0,0,0,0.2)', padding: '2px 6px', borderRadius: '10px', color: '#94a3b8' }}>
                                    {col.count}
                                </span>
                            </button>
                        ))}
                    </div>
                </div>

                {/* 2. Document List Table/Grid */}
                <div className="glass-card" style={{ display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
                    <div style={{ padding: '1rem', borderBottom: '1px solid rgba(255,255,255,0.05)', display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                        <h3 style={{ fontSize: '1rem' }}>{selectedCollection ? ICONS[selectedCollection] : ''} {selectedCollection ? ` ${selectedCollection}` : 'Select a Collection'}</h3>

                        {selectedCollection && (
                            <input
                                type="text"
                                placeholder="≡ƒöì Search documents..."
                                value={searchQuery}
                                onChange={(e) => setSearchQuery(e.target.value)}
                                style={{
                                    width: '100%',
                                    padding: '0.5rem 0.75rem',
                                    background: 'rgba(0,0,0,0.2)',
                                    border: '1px solid rgba(255,255,255,0.1)',
                                    borderRadius: '6px',
                                    color: 'white',
                                    fontSize: '0.85rem'
                                }}
                            />
                        )}
                    </div>

                    <div style={{ flex: 1, overflowY: 'auto', padding: '0.5rem 1rem' }}>
                        {loading ? (
                            <div className="spinner" style={{ margin: '2rem auto' }}></div>
                        ) : (
                            <>
                                <p style={{ fontSize: '0.75rem', color: '#64748b', marginBottom: '0.5rem', textAlign: 'right' }}>
                                    Showing {filteredDocuments.length} records
                                </p>
                                <div style={{ display: 'flex', flexDirection: 'column' }}>
                                    {filteredDocuments.map(doc => renderDocCard(doc))}
                                    {filteredDocuments.length === 0 && selectedCollection && (
                                        <div style={{ textAlign: 'center', padding: '2rem', color: '#64748b' }}>
                                            No matching documents found
                                        </div>
                                    )}
                                </div>
                            </>
                        )}
                    </div>
                </div>

                {/* 3. Editor Panel */}
                <div className="glass-card" style={{ display: 'flex', flexDirection: 'column', overflow: 'hidden', border: '1px solid rgba(255,255,255,0.1)' }}>
                    <div style={{ padding: '0.75rem 1rem', background: 'rgba(0,0,0,0.3)', borderBottom: '1px solid rgba(255,255,255,0.05)', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                            <h3 style={{ fontSize: '0.9rem', color: '#e2e8f0' }}>Object Editor</h3>
                            {selectedDoc && <span style={{ fontSize: '0.7rem', fontFamily: 'monospace', color: 'var(--accent-primary)' }}>{selectedDoc._id}</span>}
                        </div>
                        <div style={{ display: 'flex', gap: '0.5rem', alignItems: 'center' }}>
                            {status && <span style={{ fontSize: '0.8rem', color: status.includes('Error') ? '#ef4444' : '#10b981', marginRight: '0.5rem' }}>{status}</span>}
                            <button onClick={formatJSON} disabled={!selectedDoc} title="Format JSON" style={{ background: 'transparent', border: 'none', cursor: 'pointer', opacity: selectedDoc ? 1 : 0.3 }}>Γ£¿</button>
                        </div>
                    </div>

                    <div style={{ flex: 1, position: 'relative', background: '#0f172a' }}>
                        {!selectedDoc && (
                            <div style={{ position: 'absolute', inset: 0, display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#475569', flexDirection: 'column', gap: '1rem' }}>
                                <span style={{ fontSize: '2rem', opacity: 0.5 }}>≡ƒô¥</span>
                                <p>Select a document to edit</p>
                            </div>
                        )}
                        <textarea
                            value={jsonInput}
                            onChange={(e) => setJsonInput(e.target.value)}
                            disabled={!selectedDoc}
                            spellCheck={false}
                            style={{
                                width: '100%',
                                height: '100%',
                                padding: '1.5rem',
                                background: 'transparent',
                                border: 'none',
                                color: '#e2e8f0',
                                fontFamily: "'Fira Code', Consolas, Monaco, monospace",
                                fontSize: '14px',
                                lineHeight: '1.6',
                                resize: 'none',
                                outline: 'none'
                            }}
                        />
                    </div>

                    <div style={{ padding: '1rem', /* borderTop: '1px solid rgba(255,255,255,0.05)', */ background: 'rgba(0,0,0,0.2)', display: 'flex', gap: '1rem' }}>
                        <button
                            disabled={!selectedDoc}
                            onClick={handleSave}
                            className="btn-primary"
                            style={{ flex: 1, padding: '0.75rem', opacity: !selectedDoc ? 0.5 : 1, display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '0.5rem' }}
                        >
                            <span>≡ƒÆ╛</span> Save Changes
                        </button>
                        <button
                            disabled={!selectedDoc}
                            onClick={handleDelete}
                            style={{
                                padding: '0.75rem 1.5rem',
                                background: 'rgba(239, 68, 68, 0.1)',
                                border: '1px solid rgba(239, 68, 68, 0.3)',
                                color: '#fca5a5',
                                borderRadius: '8px',
                                cursor: 'pointer',
                                opacity: !selectedDoc ? 0.5 : 1,
                                transition: 'all 0.2s'
                            }}
                        >
                            ≡ƒùæ∩╕Å Delete
                        </button>
                    </div>
                </div>

            </div>
        </div>
    );
}

"use client";
import { useState, useEffect } from 'react';
import { useSession } from 'next-auth/react';
import { useRouter } from 'next/navigation';
import Image from 'next/image';
import styles from '../page.module.css';

interface LeaderboardEntry {
    rank: number;
    userId: { _id: string; name: string; username?: string; avatar: string };
    challengeId: { title: string; badge: string };
    points: number;
    wins: number;
}

export default function AdminLeaderboardsPage() {
    const { data: session, status } = useSession();
    const router = useRouter();
    const [loading, setLoading] = useState(true);
    const [leaderboard, setLeaderboard] = useState<LeaderboardEntry[]>([]);
    const [currentPage, setCurrentPage] = useState(1);
    const [totalItems, setTotalItems] = useState(0);

    useEffect(() => {
        if (status === 'unauthenticated') {
            router.push('/auth/login');
        } else if (status === 'authenticated' && session?.user?.role !== 'admin') {
            router.push('/');
        } else if (status === 'authenticated') {
            fetchLeaderboard();
        }
    }, [status, session, router, currentPage]);

    const fetchLeaderboard = async () => {
        try {
            setLoading(true);
            const res = await fetch(`/api/leaderboards?page=${currentPage}&limit=10`);
            const data = await res.json();
            if (res.ok) {
                setLeaderboard(data.leaderboard);
                setTotalItems(data.pagination.total);
            }
        } catch (error) {
            console.error('Failed to fetch leaderboard:', error);
        } finally {
            setLoading(false);
        }
    };

    if (loading || status === 'loading') {
        return (
            <div className={styles.adminDashboard}>
                <div style={{ padding: '2rem', textAlign: 'center' }}>
                    <div className="spinner"></div>
                    <p style={{ marginTop: '1rem', color: 'var(--text-secondary)' }}>Loading leaderboards...</p>
                </div>
            </div>
        );
    }

    return (
        <div className={styles.adminDashboard}>
            <header className={styles.header}>
                <div>
                    <h1 className="text-gradient">Leaderboards Management</h1>
                    <p style={{ color: 'var(--text-secondary)', marginTop: '0.5rem' }}>
                        View top participants across all challenges
                    </p>
                </div>
            </header>

            <div className="glass-card" style={{ padding: '2rem' }}>
                <div className={styles.cardHeader}>
                    <h3>≡ƒÅå Global Leaderboard</h3>
                    <div style={{ color: 'var(--text-secondary)', fontSize: '0.9rem' }}>
                        {totalItems === 0 ? '0-0' : `${(currentPage - 1) * 10 + 1}-${Math.min(currentPage * 10, totalItems)}`} of {totalItems}
                    </div>
                </div>

                <div className={styles.tableContainer}>
                    <table className={styles.table}>
                        <thead>
                            <tr>
                                <th>Rank</th>
                                <th>Challenge (Global/Specific)</th>
                                <th>User</th>
                                <th>Points</th>
                                <th>Wins</th>
                                <th>Actions</th>
                            </tr>
                        </thead>
                        <tbody>
                            {leaderboard.map((item, idx) => (
                                <tr key={idx} style={item.rank <= 3 ? { background: 'rgba(212, 175, 55, 0.06)', borderLeft: '2px solid var(--accent-primary)' } : {}}>
                                    <td>
                                        <div style={{ fontSize: '1.25rem', fontWeight: 'bold' }}>
                                            {item.rank === 1 ? '≡ƒÑç' : item.rank === 2 ? '≡ƒÑê' : item.rank === 3 ? '≡ƒÑë' : item.rank}
                                        </div>
                                    </td>
                                    <td>
                                        <div>
                                            {item.challengeId?.badge === 'Prize' && <span style={{ color: '#f59e0b', fontSize: '0.75rem', fontWeight: 600, display: 'block' }}>≡ƒÅå Prize</span>}
                                            <span style={{ fontWeight: 500 }}>{item.challengeId?.title || 'Global'}</span>
                                        </div>
                                    </td>
                                    <td>
                                        <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                                            <div style={{ width: 32, height: 32, position: 'relative', borderRadius: '50%', overflow: 'hidden' }}>
                                                <Image
                                                    src={item.userId?.avatar || `https://ui-avatars.com/api/?name=${encodeURIComponent(item.userId?.name || 'User')}`}
                                                    alt={item.userId?.name || 'User'}
                                                    fill
                                                    style={{ objectFit: 'cover' }}
                                                    unoptimized
                                                />
                                            </div>
                                            <div style={{ display: 'flex', flexDirection: 'column' }}>
                                                <span style={{ fontWeight: 500 }}>
                                                    {item.userId?.username ? `@${item.userId.username}` : (item.userId?.name || 'User')}
                                                </span>
                                            </div>
                                        </div>
                                    </td>
                                    <td>
                                        <span style={{ fontWeight: 600, color: 'var(--text-primary)' }}>{item.points.toLocaleString()} pts</span>
                                    </td>
                                    <td>
                                        <span style={{ fontWeight: 600 }}>{item.wins}</span>
                                    </td>
                                    <td>
                                        <button
                                            className={styles.actionBtn}
                                            onClick={() => {
                                                const handle = item.userId?.username || item.userId?.name;
                                                if (handle) {
                                                    router.push(`/users/${encodeURIComponent(handle)}`);
                                                } else {
                                                    alert('Username not available for this user.');
                                                }
                                            }}
                                        >View Profile</button>
                                    </td>
                                </tr>
                            ))}
                            {leaderboard.length === 0 && (
                                <tr>
                                    <td colSpan={6} style={{ textAlign: 'center', padding: '2rem', color: 'var(--text-secondary)' }}>No records found</td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>

                {/* Bottom Pagination */}
                <div style={{ display: 'flex', justifyContent: 'space-between', marginTop: '1.5rem', paddingTop: '1.5rem', borderTop: '1px solid rgba(255, 255, 255, 0.06)' }}>
                    <button
                        className={styles.actionBtn}
                        onClick={() => setCurrentPage(prev => Math.max(1, prev - 1))}
                        disabled={currentPage === 1}
                        style={{ opacity: currentPage === 1 ? 0.5 : 1, cursor: currentPage === 1 ? 'not-allowed' : 'pointer' }}
                    >ΓåÉ Prev</button>
                    <button
                        className={styles.actionBtn}
                        onClick={() => setCurrentPage(prev => prev + 1)}
                        disabled={(currentPage * 10) >= totalItems}
                        style={{ opacity: (currentPage * 10) >= totalItems ? 0.5 : 1, cursor: (currentPage * 10) >= totalItems ? 'not-allowed' : 'pointer', background: 'var(--gradient-main)', color: 'black', fontWeight: 600 }}
                    >Next ΓåÆ</button>
                </div>
            </div>
        </div>
    );
}

"use client";
import { useState, useEffect } from 'react';
import { useSession } from 'next-auth/react';
import { useRouter } from 'next/navigation';
import Image from 'next/image';
import styles from '../page.module.css';

interface Subscriber {
    _id: string;
    userId: {
        _id: string;
        name: string;
        email: string;
        avatar: string;
        username?: string;
    };
    plan: string;
    price: number;
    status: string;
    currentPeriodEnd: string;
}

export default function AdminSubscribersPage() {
    const { data: session, status } = useSession();
    const router = useRouter();
    const [loading, setLoading] = useState(true);
    const [subscribers, setSubscribers] = useState<Subscriber[]>([]);
    const [currentPage, setCurrentPage] = useState(1);
    const [totalItems, setTotalItems] = useState(0);

    useEffect(() => {
        if (status === 'unauthenticated') {
            router.push('/auth/login');
        } else if (status === 'authenticated' && session?.user?.role !== 'admin') {
            router.push('/');
        } else if (status === 'authenticated') {
            fetchSubscribers();
        }
    }, [status, session, router, currentPage]);

    const fetchSubscribers = async () => {
        try {
            setLoading(true);
            const res = await fetch(`/api/admin/subscribers?page=${currentPage}&limit=10`);
            const data = await res.json();
            if (res.ok) {
                setSubscribers(data.subscriptions);
                setTotalItems(data.pagination.total);
            }
        } catch (error) {
            console.error('Failed to fetch subscribers:', error);
        } finally {
            setLoading(false);
        }
    };

    if (loading || status === 'loading') {
        return (
            <div className={styles.adminDashboard}>
                <div style={{ padding: '2rem', textAlign: 'center' }}>
                    <div className="spinner"></div>
                    <p style={{ marginTop: '1rem', color: 'var(--text-secondary)' }}>Loading subscribers...</p>
                </div>
            </div>
        );
    }

    return (
        <div className={styles.adminDashboard}>
            <header className={styles.header}>
                <div>
                    <h1 className="text-gradient">Subscribers Management</h1>
                    <p style={{ color: 'var(--text-secondary)', marginTop: '0.5rem' }}>
                        Manage platform subscribers and recurring revenue
                    </p>
                </div>
            </header>

            <div className="glass-card" style={{ padding: '2rem' }}>
                <div className={styles.cardHeader}>
                    <h3>≡ƒæÑ Active Subscribers</h3>
                    <div style={{ color: 'var(--text-secondary)', fontSize: '0.9rem' }}>
                        {totalItems === 0 ? '0-0' : `${(currentPage - 1) * 10 + 1}-${Math.min(currentPage * 10, totalItems)}`} of {totalItems}
                    </div>
                </div>

                <div className={styles.tableContainer}>
                    <table className={styles.table}>
                        <thead>
                            <tr>
                                <th>User</th>
                                <th>Plan</th>
                                <th>Amount</th>
                                <th>Status</th>
                                <th>Expiry</th>
                                <th>Actions</th>
                            </tr>
                        </thead>
                        <tbody>
                            {subscribers.map((sub) => (
                                <tr key={sub._id}>
                                    <td>
                                        <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                                            <div style={{ width: 32, height: 32, position: 'relative', borderRadius: '50%', overflow: 'hidden' }}>
                                                <Image
                                                    src={sub.userId?.avatar || `https://ui-avatars.com/api/?name=${encodeURIComponent(sub.userId?.name || 'User')}`}
                                                    alt={sub.userId?.name || 'User'}
                                                    fill
                                                    style={{ objectFit: 'cover' }}
                                                    unoptimized
                                                />
                                            </div>
                                            <div style={{ display: 'flex', flexDirection: 'column' }}>
                                                <span style={{ fontWeight: 500 }}>{sub.userId?.name}</span>
                                                <span style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>{sub.userId?.email}</span>
                                            </div>
                                        </div>
                                    </td>
                                    <td>
                                        <span style={{
                                            textTransform: 'capitalize',
                                            padding: '0.25rem 0.5rem',
                                            borderRadius: '4px',
                                            fontSize: '0.8rem',
                                            background: 'rgba(212, 175, 55, 0.1)',
                                            color: 'var(--accent-primary)',
                                            fontWeight: 600
                                        }}>
                                            {sub.plan.replace('_', ' ')}
                                        </span>
                                    </td>
                                    <td>
                                        <span style={{ fontWeight: 600 }}>${(sub.price / 100).toFixed(2)}</span>
                                    </td>
                                    <td>
                                        <span className={`${styles.statusBadge} ${styles[sub.status] || ''}`} style={{
                                            background: sub.status === 'active' ? 'rgba(16, 185, 129, 0.1)' : 'rgba(239, 68, 68, 0.1)',
                                            color: sub.status === 'active' ? '#10b981' : '#ef4444',
                                            border: `1px solid ${sub.status === 'active' ? 'rgba(16, 185, 129, 0.2)' : 'rgba(239, 68, 68, 0.2)'}`,
                                            padding: '0.25rem 0.6rem',
                                            borderRadius: '100px',
                                            fontSize: '0.75rem'
                                        }}>
                                            {sub.status.toUpperCase()}
                                        </span>
                                    </td>
                                    <td>
                                        <span style={{ fontSize: '0.85rem' }}>
                                            {new Date(sub.currentPeriodEnd).toLocaleDateString()}
                                        </span>
                                    </td>
                                    <td>
                                        <button
                                            className={styles.actionBtn}
                                            onClick={() => {
                                                const action = confirm(`Manage subscription for ${sub.userId?.name}?\n\nPlan: ${sub.plan}\nStatus: ${sub.status}\n\nClick OK to cancel their subscription, or Cancel to go back.`);
                                                if (action) alert('Subscription cancellation initiated. (Connect Stripe webhook to fully implement.)');
                                            }}
                                        >Manage</button>
                                    </td>
                                </tr>
                            ))}
                            {subscribers.length === 0 && (
                                <tr>
                                    <td colSpan={6} style={{ textAlign: 'center', padding: '2rem', color: 'var(--text-secondary)' }}>No subscribers found</td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>

                {/* Pagination */}
                <div style={{ display: 'flex', justifyContent: 'space-between', marginTop: '1.5rem', paddingTop: '1.5rem', borderTop: '1px solid rgba(255, 255, 255, 0.06)' }}>
                    <button
                        className={styles.actionBtn}
                        onClick={() => setCurrentPage(prev => Math.max(1, prev - 1))}
                        disabled={currentPage === 1}
                        style={{ opacity: currentPage === 1 ? 0.5 : 1 }}
                    >ΓåÉ Prev</button>
                    <button
                        className={styles.actionBtn}
                        onClick={() => setCurrentPage(prev => prev + 1)}
                        disabled={(currentPage * 10) >= totalItems}
                        style={{ opacity: (currentPage * 10) >= totalItems ? 0.5 : 1, background: 'var(--gradient-main)', color: 'black' }}
                    >Next ΓåÆ</button>
                </div>
            </div>
        </div>
    );
}

"use client";
import { useState, useEffect, useCallback } from 'react';
import { useSession } from 'next-auth/react';
import { useRouter } from 'next/navigation';
import styles from '../page.module.css';

interface Reply {
    message: string;
    isAdmin: boolean;
    authorName: string;
    createdAt: string;
}

interface Ticket {
    _id: string;
    ticketId: string;
    userName: string;
    userEmail: string;
    subject: string;
    message: string;
    category: string;
    priority: string;
    status: string;
    replies: Reply[];
    createdAt: string;
}

interface Stats {
    open: number;
    inProgress: number;
    resolved: number;
    closed: number;
}

const PRIORITY_COLORS: Record<string, string> = {
    urgent: '#ef4444',
    high: '#f97316',
    medium: '#f59e0b',
    low: '#10b981',
};

const STATUS_STYLES: Record<string, { bg: string; color: string; border: string }> = {
    open: { bg: 'rgba(239,68,68,0.1)', color: '#ef4444', border: 'rgba(239,68,68,0.3)' },
    'in-progress': { bg: 'rgba(245,158,11,0.1)', color: '#f59e0b', border: 'rgba(245,158,11,0.3)' },
    resolved: { bg: 'rgba(16,185,129,0.1)', color: '#10b981', border: 'rgba(16,185,129,0.3)' },
    closed: { bg: 'rgba(107,114,128,0.1)', color: '#6b7280', border: 'rgba(107,114,128,0.3)' },
};

export default function AdminSupportPage() {
    const { data: session, status } = useSession();
    const router = useRouter();
    const [loading, setLoading] = useState(true);
    const [tickets, setTickets] = useState<Ticket[]>([]);
    const [stats, setStats] = useState<Stats>({ open: 0, inProgress: 0, resolved: 0, closed: 0 });
    const [filterStatus, setFilterStatus] = useState('all');
    const [filterCategory, setFilterCategory] = useState('all');
    const [filterPriority, setFilterPriority] = useState('all');
    const [selectedTicket, setSelectedTicket] = useState<Ticket | null>(null);
    const [replyText, setReplyText] = useState('');
    const [replying, setReplying] = useState(false);
    const [toast, setToast] = useState('');
    const [seeding, setSeeding] = useState(false);

    const showToast = (msg: string) => {
        setToast(msg);
        setTimeout(() => setToast(''), 3000);
    };

    const fetchTickets = useCallback(async () => {
        try {
            setLoading(true);
            const params = new URLSearchParams();
            if (filterStatus !== 'all') params.set('status', filterStatus);
            if (filterCategory !== 'all') params.set('category', filterCategory);
            if (filterPriority !== 'all') params.set('priority', filterPriority);

            const res = await fetch(`/api/admin/support?${params}`);
            const data = await res.json();
            if (res.ok) {
                setTickets(data.tickets);
                setStats(data.stats || { open: 0, inProgress: 0, resolved: 0, closed: 0 });
            }
        } catch (error) {
            console.error('Failed to fetch tickets:', error);
        } finally {
            setLoading(false);
        }
    }, [filterStatus, filterCategory, filterPriority]);

    useEffect(() => {
        if (status === 'unauthenticated') router.push('/auth/login');
        else if (status === 'authenticated' && session?.user?.role !== 'admin') router.push('/');
        else if (status === 'authenticated') fetchTickets();
    }, [status, session, router, fetchTickets]);

    const handleStatusChange = async (ticketId: string, newStatus: string) => {
        try {
            const res = await fetch(`/api/admin/support/${ticketId}`, {
                method: 'PATCH',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ status: newStatus }),
            });
            if (res.ok) {
                setTickets(prev => prev.map(t => t.ticketId === ticketId ? { ...t, status: newStatus } : t));
                if (selectedTicket?.ticketId === ticketId) {
                    setSelectedTicket(prev => prev ? { ...prev, status: newStatus } : null);
                }
                showToast(`Status updated to ${newStatus}`);
            }
        } catch (error) {
            showToast('Failed to update status');
        }
    };

    const handleReply = async () => {
        if (!selectedTicket || !replyText.trim()) return;
        setReplying(true);
        try {
            const res = await fetch(`/api/admin/support/${selectedTicket.ticketId}`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ message: replyText }),
            });
            const data = await res.json();
            if (res.ok) {
                const updatedTicket = { ...selectedTicket, replies: [...selectedTicket.replies, data.reply], status: 'in-progress' };
                setSelectedTicket(updatedTicket);
                setTickets(prev => prev.map(t => t.ticketId === selectedTicket.ticketId ? updatedTicket : t));
                setReplyText('');
                showToast('Reply sent successfully!');
            } else {
                showToast(data.error || 'Failed to send reply');
            }
        } catch {
            showToast('Error sending reply');
        } finally {
            setReplying(false);
        }
    };

    const handleDelete = async (ticketId: string) => {
        if (!confirm(`Delete ticket ${ticketId}? This cannot be undone.`)) return;
        try {
            const res = await fetch(`/api/admin/support/${ticketId}`, { method: 'DELETE' });
            if (res.ok) {
                setTickets(prev => prev.filter(t => t.ticketId !== ticketId));
                if (selectedTicket?.ticketId === ticketId) setSelectedTicket(null);
                showToast('Ticket deleted');
            }
        } catch {
            showToast('Failed to delete ticket');
        }
    };

    const handleSeedData = async () => {
        setSeeding(true);
        try {
            const res = await fetch('/api/admin/support', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ action: 'seed' }),
            });
            if (res.ok) {
                showToast('Sample tickets added!');
                fetchTickets();
            }
        } catch {
            showToast('Failed to seed data');
        } finally {
            setSeeding(false);
        }
    };

    const getRelativeTime = (dateStr: string) => {
        const diff = Date.now() - new Date(dateStr).getTime();
        const mins = Math.floor(diff / 60000);
        if (mins < 1) return 'just now';
        if (mins < 60) return `${mins}m ago`;
        const hours = Math.floor(mins / 60);
        if (hours < 24) return `${hours}h ago`;
        return `${Math.floor(hours / 24)}d ago`;
    };

    if (loading || status === 'loading') {
        return (
            <div className={styles.adminDashboard}>
                <div style={{ padding: '2rem', textAlign: 'center' }}>
                    <div className="spinner"></div>
                    <p style={{ marginTop: '1rem', color: 'var(--text-secondary)' }}>Loading tickets...</p>
                </div>
            </div>
        );
    }

    return (
        <div className={styles.adminDashboard}>
            {/* Toast Notification */}
            {toast && (
                <div style={{
                    position: 'fixed', top: '1.5rem', right: '1.5rem', zIndex: 9999,
                    background: 'var(--gradient-main)', color: 'black',
                    padding: '0.75rem 1.5rem', borderRadius: '10px', fontWeight: 600,
                    boxShadow: '0 4px 20px rgba(212,175,55,0.4)', animation: 'none',
                }}>
                    Γ£ô {toast}
                </div>
            )}

            {/* Reply / Detail Modal */}
            {selectedTicket && (
                <div style={{
                    position: 'fixed', inset: 0, background: 'rgba(0,0,0,0.85)',
                    zIndex: 1000, display: 'flex', alignItems: 'center', justifyContent: 'center',
                    padding: '1rem',
                }}>
                    <div className="glass-card" style={{
                        width: '100%', maxWidth: '680px', maxHeight: '85vh',
                        display: 'flex', flexDirection: 'column', overflow: 'hidden',
                    }}>
                        {/* Modal Header */}
                        <div style={{
                            padding: '1.5rem', borderBottom: '1px solid rgba(255,255,255,0.07)',
                            display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', flexShrink: 0,
                        }}>
                            <div>
                                <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', marginBottom: '0.4rem' }}>
                                    <span style={{ color: 'var(--text-muted)', fontSize: '0.85rem' }}>{selectedTicket.ticketId}</span>
                                    <span style={{
                                        fontSize: '0.7rem', fontWeight: 700, padding: '0.15rem 0.5rem',
                                        borderRadius: '4px', textTransform: 'uppercase',
                                        background: STATUS_STYLES[selectedTicket.status]?.bg,
                                        color: STATUS_STYLES[selectedTicket.status]?.color,
                                        border: `1px solid ${STATUS_STYLES[selectedTicket.status]?.border}`,
                                    }}>{selectedTicket.status}</span>
                                    <span style={{
                                        fontSize: '0.7rem', fontWeight: 700, padding: '0.15rem 0.5rem',
                                        borderRadius: '4px', textTransform: 'capitalize',
                                        color: PRIORITY_COLORS[selectedTicket.priority],
                                        background: `${PRIORITY_COLORS[selectedTicket.priority]}20`,
                                    }}>ΓÜí {selectedTicket.priority}</span>
                                </div>
                                <h3 style={{ fontSize: '1.1rem', marginBottom: '0.25rem' }}>{selectedTicket.subject}</h3>
                                <p style={{ fontSize: '0.8rem', color: 'var(--text-muted)' }}>
                                    {selectedTicket.userName} ┬╖ {selectedTicket.userEmail} ┬╖ {getRelativeTime(selectedTicket.createdAt)}
                                </p>
                            </div>
                            <button onClick={() => setSelectedTicket(null)} style={{
                                background: 'rgba(255,255,255,0.07)', border: 'none', color: 'var(--text-secondary)',
                                width: 32, height: 32, borderRadius: '50%', cursor: 'pointer', fontSize: '1rem',
                                display: 'flex', alignItems: 'center', justifyContent: 'center',
                            }}>Γ£ò</button>
                        </div>

                        {/* Conversation Thread */}
                        <div style={{ flex: 1, overflowY: 'auto', padding: '1.5rem', display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                            {/* Original message */}
                            <div style={{
                                background: 'rgba(255,255,255,0.04)', borderRadius: '10px', padding: '1rem',
                                border: '1px solid rgba(255,255,255,0.06)',
                            }}>
                                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '0.5rem' }}>
                                    <span style={{ fontWeight: 600, fontSize: '0.9rem' }}>{selectedTicket.userName}</span>
                                    <span style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>{getRelativeTime(selectedTicket.createdAt)}</span>
                                </div>
                                <p style={{ color: 'var(--text-secondary)', fontSize: '0.9rem', lineHeight: 1.6 }}>{selectedTicket.message}</p>
                            </div>

                            {/* Replies */}
                            {selectedTicket.replies.map((reply, idx) => (
                                <div key={idx} style={{
                                    background: reply.isAdmin ? 'rgba(212,175,55,0.06)' : 'rgba(255,255,255,0.04)',
                                    borderRadius: '10px', padding: '1rem',
                                    border: reply.isAdmin ? '1px solid rgba(212,175,55,0.2)' : '1px solid rgba(255,255,255,0.06)',
                                    marginLeft: reply.isAdmin ? '2rem' : 0,
                                }}>
                                    <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '0.5rem' }}>
                                        <span style={{ fontWeight: 600, fontSize: '0.9rem', color: reply.isAdmin ? 'var(--accent-primary)' : 'inherit' }}>
                                            {reply.isAdmin ? '≡ƒ¢í∩╕Å Admin ΓÇö ' : ''}{reply.authorName}
                                        </span>
                                        <span style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>{getRelativeTime(reply.createdAt)}</span>
                                    </div>
                                    <p style={{ color: 'var(--text-secondary)', fontSize: '0.9rem', lineHeight: 1.6 }}>{reply.message}</p>
                                </div>
                            ))}
                        </div>

                        {/* Status Controls */}
                        <div style={{ padding: '1rem 1.5rem', borderTop: '1px solid rgba(255,255,255,0.06)', background: 'rgba(0,0,0,0.2)', flexShrink: 0 }}>
                            <div style={{ display: 'flex', gap: '0.5rem', marginBottom: '0.75rem', flexWrap: 'wrap' }}>
                                {['open', 'in-progress', 'resolved', 'closed'].map(s => (
                                    <button key={s} onClick={() => handleStatusChange(selectedTicket.ticketId, s)} style={{
                                        padding: '0.3rem 0.75rem', fontSize: '0.75rem', fontWeight: 600,
                                        borderRadius: '6px', cursor: 'pointer', textTransform: 'capitalize',
                                        border: `1px solid ${STATUS_STYLES[s]?.border}`,
                                        background: selectedTicket.status === s ? STATUS_STYLES[s]?.bg : 'transparent',
                                        color: STATUS_STYLES[s]?.color,
                                        opacity: selectedTicket.status === s ? 1 : 0.6,
                                    }}>
                                        {selectedTicket.status === s ? 'Γ£ô ' : ''}{s}
                                    </button>
                                ))}
                            </div>
                            {/* Reply Input */}
                            <div style={{ display: 'flex', gap: '0.75rem' }}>
                                <textarea
                                    value={replyText}
                                    onChange={e => setReplyText(e.target.value)}
                                    placeholder="Type your reply to the user..."
                                    rows={2}
                                    style={{
                                        flex: 1, background: 'rgba(255,255,255,0.05)',
                                        border: '1px solid rgba(255,255,255,0.1)', borderRadius: '8px',
                                        padding: '0.6rem 0.8rem', color: 'white', resize: 'none',
                                        fontSize: '0.9rem', outline: 'none',
                                    }}
                                    onKeyDown={e => { if (e.key === 'Enter' && e.ctrlKey) handleReply(); }}
                                />
                                <button
                                    onClick={handleReply}
                                    disabled={replying || !replyText.trim()}
                                    style={{
                                        padding: '0 1rem', background: 'var(--gradient-main)',
                                        border: 'none', borderRadius: '8px', color: 'black',
                                        fontWeight: 700, cursor: replying || !replyText.trim() ? 'not-allowed' : 'pointer',
                                        opacity: replying || !replyText.trim() ? 0.6 : 1, fontSize: '0.85rem',
                                        whiteSpace: 'nowrap',
                                    }}
                                >
                                    {replying ? 'Sending...' : 'Send Γå⌐'}
                                </button>
                            </div>
                            <p style={{ fontSize: '0.7rem', color: 'var(--text-muted)', marginTop: '0.3rem' }}>Ctrl+Enter to send</p>
                        </div>
                    </div>
                </div>
            )}

            {/* Page Header */}
            <header className={styles.header}>
                <div>
                    <h1 className="text-gradient">Support Tickets</h1>
                    <p style={{ color: 'var(--text-secondary)', marginTop: '0.5rem' }}>
                        Manage user inquiries and technical support
                    </p>
                </div>
                {tickets.length === 0 && (
                    <button
                        className="btn-primary"
                        onClick={handleSeedData}
                        disabled={seeding}
                        style={{ opacity: seeding ? 0.7 : 1 }}
                    >
                        {seeding ? 'Adding...' : '+ Add Sample Tickets'}
                    </button>
                )}
            </header>

            {/* Stats Bar */}
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: '1rem', marginBottom: '1.5rem' }}>
                {[
                    { label: 'Open', count: stats.open, color: '#ef4444' },
                    { label: 'In Progress', count: stats.inProgress, color: '#f59e0b' },
                    { label: 'Resolved', count: stats.resolved, color: '#10b981' },
                    { label: 'Closed', count: stats.closed, color: '#6b7280' },
                ].map(s => (
                    <div key={s.label} className="glass-card" style={{ padding: '1rem', textAlign: 'center', cursor: 'pointer' }}
                        onClick={() => setFilterStatus(s.label.toLowerCase().replace(' ', '-'))}>
                        <p style={{ fontSize: '1.8rem', fontWeight: 700, color: s.color }}>{s.count}</p>
                        <p style={{ fontSize: '0.8rem', color: 'var(--text-muted)', marginTop: '0.2rem' }}>{s.label}</p>
                    </div>
                ))}
            </div>

            {/* Filters */}
            <div className="glass-card" style={{ padding: '1rem 1.5rem', marginBottom: '1.5rem', display: 'flex', gap: '0.75rem', flexWrap: 'wrap', alignItems: 'center' }}>
                <span style={{ color: 'var(--text-muted)', fontSize: '0.85rem' }}>Filter:</span>
                {/* Status filter */}
                <select value={filterStatus} onChange={e => setFilterStatus(e.target.value)}
                    style={{ background: 'rgba(255,255,255,0.06)', border: '1px solid rgba(255,255,255,0.1)', borderRadius: '6px', color: 'white', padding: '0.4rem 0.75rem', cursor: 'pointer', fontSize: '0.85rem' }}>
                    <option value="all">All Status</option>
                    <option value="open">Open</option>
                    <option value="in-progress">In Progress</option>
                    <option value="resolved">Resolved</option>
                    <option value="closed">Closed</option>
                </select>
                {/* Category filter */}
                <select value={filterCategory} onChange={e => setFilterCategory(e.target.value)}
                    style={{ background: 'rgba(255,255,255,0.06)', border: '1px solid rgba(255,255,255,0.1)', borderRadius: '6px', color: 'white', padding: '0.4rem 0.75rem', cursor: 'pointer', fontSize: '0.85rem' }}>
                    <option value="all">All Categories</option>
                    <option value="payment">Payment</option>
                    <option value="technical">Technical</option>
                    <option value="account">Account</option>
                    <option value="badge">Badge</option>
                    <option value="challenge">Challenge</option>
                    <option value="other">Other</option>
                </select>
                {/* Priority filter */}
                <select value={filterPriority} onChange={e => setFilterPriority(e.target.value)}
                    style={{ background: 'rgba(255,255,255,0.06)', border: '1px solid rgba(255,255,255,0.1)', borderRadius: '6px', color: 'white', padding: '0.4rem 0.75rem', cursor: 'pointer', fontSize: '0.85rem' }}>
                    <option value="all">All Priority</option>
                    <option value="urgent">Urgent</option>
                    <option value="high">High</option>
                    <option value="medium">Medium</option>
                    <option value="low">Low</option>
                </select>
                {(filterStatus !== 'all' || filterCategory !== 'all' || filterPriority !== 'all') && (
                    <button onClick={() => { setFilterStatus('all'); setFilterCategory('all'); setFilterPriority('all'); }}
                        style={{ background: 'transparent', border: '1px solid rgba(255,255,255,0.1)', borderRadius: '6px', color: 'var(--text-secondary)', padding: '0.4rem 0.75rem', cursor: 'pointer', fontSize: '0.8rem' }}>
                        Γ£ò Clear Filters
                    </button>
                )}
                <span style={{ marginLeft: 'auto', color: 'var(--text-muted)', fontSize: '0.85rem' }}>{tickets.length} tickets</span>
            </div>

            {/* Tickets Table */}
            <div className="glass-card" style={{ padding: '0', overflow: 'hidden' }}>
                {tickets.length === 0 ? (
                    <div style={{ padding: '3rem', textAlign: 'center' }}>
                        <p style={{ fontSize: '2rem', marginBottom: '0.5rem' }}>≡ƒô¡</p>
                        <p style={{ color: 'var(--text-secondary)', fontSize: '1rem', marginBottom: '1rem' }}>No support tickets found</p>
                        <button className="btn-primary" onClick={handleSeedData} disabled={seeding}>
                            {seeding ? 'Adding...' : 'Load Sample Tickets'}
                        </button>
                    </div>
                ) : (
                    <div className={styles.tableContainer}>
                        <table className={styles.table}>
                            <thead>
                                <tr>
                                    <th>ID</th>
                                    <th>User</th>
                                    <th>Subject</th>
                                    <th>Category</th>
                                    <th>Priority</th>
                                    <th>Status</th>
                                    <th>Replies</th>
                                    <th>Time</th>
                                    <th>Actions</th>
                                </tr>
                            </thead>
                            <tbody>
                                {tickets.map((ticket) => (
                                    <tr key={ticket._id} style={{ cursor: 'pointer' }} onClick={() => setSelectedTicket(ticket)}>
                                        <td><span style={{ color: 'var(--accent-primary)', fontSize: '0.8rem', fontWeight: 600 }}>{ticket.ticketId}</span></td>
                                        <td>
                                            <div>
                                                <div style={{ fontWeight: 600, fontSize: '0.9rem' }}>{ticket.userName}</div>
                                                <div style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>{ticket.userEmail}</div>
                                            </div>
                                        </td>
                                        <td><span style={{ fontWeight: 500, fontSize: '0.9rem' }}>{ticket.subject}</span></td>
                                        <td>
                                            <span style={{ fontSize: '0.75rem', padding: '0.2rem 0.5rem', background: 'rgba(255,255,255,0.05)', borderRadius: '4px', textTransform: 'capitalize' }}>
                                                {ticket.category}
                                            </span>
                                        </td>
                                        <td>
                                            <div style={{ display: 'flex', alignItems: 'center', gap: '0.4rem' }}>
                                                <div style={{ width: 8, height: 8, borderRadius: '50%', background: PRIORITY_COLORS[ticket.priority], flexShrink: 0 }} />
                                                <span style={{ textTransform: 'capitalize', fontSize: '0.85rem' }}>{ticket.priority}</span>
                                            </div>
                                        </td>
                                        <td onClick={e => e.stopPropagation()}>
                                            <select
                                                value={ticket.status}
                                                onChange={e => handleStatusChange(ticket.ticketId, e.target.value)}
                                                style={{
                                                    background: STATUS_STYLES[ticket.status]?.bg,
                                                    border: `1px solid ${STATUS_STYLES[ticket.status]?.border}`,
                                                    color: STATUS_STYLES[ticket.status]?.color,
                                                    borderRadius: '5px', padding: '0.2rem 0.5rem',
                                                    cursor: 'pointer', fontSize: '0.75rem', fontWeight: 700,
                                                    textTransform: 'uppercase',
                                                }}
                                            >
                                                <option value="open">OPEN</option>
                                                <option value="in-progress">IN-PROGRESS</option>
                                                <option value="resolved">RESOLVED</option>
                                                <option value="closed">CLOSED</option>
                                            </select>
                                        </td>
                                        <td>
                                            <span style={{ fontSize: '0.85rem', color: ticket.replies?.length > 0 ? 'var(--accent-primary)' : 'var(--text-muted)' }}>
                                                ≡ƒÆ¼ {ticket.replies?.length || 0}
                                            </span>
                                        </td>
                                        <td><span style={{ fontSize: '0.8rem', color: 'var(--text-muted)' }}>{getRelativeTime(ticket.createdAt)}</span></td>
                                        <td onClick={e => e.stopPropagation()}>
                                            <div style={{ display: 'flex', gap: '0.4rem' }}>
                                                <button
                                                    className={styles.actionBtn}
                                                    onClick={() => setSelectedTicket(ticket)}
                                                    style={{ background: 'var(--gradient-main)', color: 'black', fontWeight: 700, border: 'none' }}
                                                >Reply</button>
                                                <button
                                                    onClick={() => handleDelete(ticket.ticketId)}
                                                    style={{
                                                        padding: '0.35rem 0.6rem', background: 'rgba(239,68,68,0.1)',
                                                        border: '1px solid rgba(239,68,68,0.3)', borderRadius: '6px',
                                                        color: '#ef4444', cursor: 'pointer', fontSize: '0.8rem',
                                                    }}
                                                >Γ£ò</button>
                                            </div>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                )}
            </div>
        </div>
    );
}

"use client";
import { useState, useEffect } from 'react';
import { useSession } from 'next-auth/react';
import { useRouter } from 'next/navigation';
import Image from 'next/image';
import styles from '../page.module.css';

interface Winner {
    _id: string;
    userId: {
        _id: string;
        name: string;
        email: string;
        avatar: string;
    };
    challengeId: {
        _id: string;
        title: string;
        badge: string;
        prize?: { amount: number; currency: string };
    };
    mediaUrl: string;
    votes: number;
    status: string;
    isWinner: boolean;
}

export default function AdminWinnersPage() {
    const { data: session, status } = useSession();
    const router = useRouter();
    const [loading, setLoading] = useState(true);
    const [winners, setWinners] = useState<Winner[]>([]);

    useEffect(() => {
        if (status === 'unauthenticated') {
            router.push('/auth/login');
        } else if (status === 'authenticated' && session?.user?.role !== 'admin') {
            router.push('/');
        } else if (status === 'authenticated') {
            fetchWinners();
        }
    }, [status, session, router]);

    const fetchWinners = async () => {
        try {
            setLoading(true);
            const res = await fetch('/api/submissions?limit=100');
            const data = await res.json();

            if (res.ok) {
                // Show ALL submissions sorted by votes so admin can pick winners
                const submissions = data.submissions
                    .sort((a: any, b: any) => b.votes - a.votes);

                setWinners(submissions);
            }
        } catch (error) {
            console.error('Error fetching winners:', error);
        } finally {
            setLoading(false);
        }
    };

    const approveSubmission = async (submissionId: string) => {
        try {
            const res = await fetch(`/api/admin/submissions/${submissionId}/approve`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
            });
            if (res.ok) {
                setWinners(prev => prev.map(w =>
                    w._id === submissionId ? { ...w, status: 'approved' } : w
                ));
            }
        } catch (error) {
            console.error('Error approving submission:', error);
        }
    };

    const toggleWinner = async (submissionId: string, currentStatus: boolean) => {
        try {
            const res = await fetch('/api/admin/submissions/winner', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ submissionId, isWinner: !currentStatus }),
            });

            if (res.ok) {
                setWinners(prev => prev.map(w =>
                    w._id === submissionId ? { ...w, isWinner: !currentStatus } : w
                ));
            }
        } catch (error) {
            console.error('Error toggling winner:', error);
        }
    };

    if (loading || status === 'loading') {
        return (
            <div className={styles.adminDashboard}>
                <div style={{ padding: '2rem', textAlign: 'center' }}>
                    <div className="spinner"></div>
                    <p style={{ marginTop: '1rem', color: 'var(--text-secondary)' }}>Loading winners...</p>
                </div>
            </div>
        );
    }

    return (
        <div className={styles.adminDashboard}>
            <header className={styles.header}>
                <div>
                    <h1 className="text-gradient">Winners Management</h1>
                    <p style={{ color: 'var(--text-secondary)', marginTop: '0.5rem' }}>
                        Manage challenge winners and prize distributions
                    </p>
                </div>
            </header>

            <div className="glass-card" style={{ padding: '2rem' }}>
                <div className={styles.cardHeader} style={{ marginBottom: '1.5rem' }}>
                    <h3>≡ƒÅå All Submissions ΓÇö Select Winners</h3>
                    <span style={{ fontSize: '0.9rem', color: 'var(--text-secondary)' }}>{winners.length} total</span>
                </div>

                {winners.length === 0 ? (
                    <p style={{ color: 'var(--text-secondary)', textAlign: 'center', padding: '2rem' }}>
                        No submissions found
                    </p>
                ) : (
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                        {winners.map((winner, idx) => (
                            <div key={winner._id} className="glass-card" style={{
                                padding: '1.5rem',
                                display: 'flex',
                                gap: '1.5rem',
                                alignItems: 'center',
                                background: winner.isWinner ? 'rgba(212, 175, 55, 0.08)' : undefined,
                                border: winner.isWinner ? '1px solid var(--accent-primary)' : undefined,
                            }}>
                                {/* Rank */}
                                <div style={{
                                    fontSize: '2rem',
                                    minWidth: '60px',
                                    textAlign: 'center',
                                }}>
                                    {idx === 0 ? '≡ƒÑç' : idx === 1 ? '≡ƒÑê' : idx === 2 ? '≡ƒÑë' : `#${idx + 1}`}
                                </div>

                                {/* Submission Image */}
                                <div style={{
                                    position: 'relative',
                                    width: '120px',
                                    height: '140px',
                                    borderRadius: '8px',
                                    overflow: 'hidden',
                                    flexShrink: 0,
                                    border: '1px solid rgba(255, 255, 255, 0.1)'
                                }}>
                                    <Image
                                        src={winner.mediaUrl}
                                        alt="Submission"
                                        fill
                                        style={{ objectFit: 'cover' }}
                                        unoptimized
                                    />
                                    {winner.isWinner && (
                                        <div style={{
                                            position: 'absolute',
                                            top: 0,
                                            right: 0,
                                            padding: '4px 8px',
                                            background: 'var(--accent-primary)',
                                            color: 'black',
                                            fontSize: '0.7rem',
                                            fontWeight: 'bold',
                                            borderBottomLeftRadius: '8px'
                                        }}>WINNER</div>
                                    )}
                                </div>

                                {/* User Info */}
                                <div style={{ flex: 1 }}>
                                    <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', marginBottom: '0.5rem' }}>
                                        <div style={{
                                            position: 'relative',
                                            width: '32px',
                                            height: '32px',
                                            borderRadius: '50%',
                                            overflow: 'hidden',
                                        }}>
                                            <Image
                                                src={winner.userId?.avatar || `https://ui-avatars.com/api/?name=${winner.userId?.name}`}
                                                alt={winner.userId?.name}
                                                fill
                                                style={{ objectFit: 'cover' }}
                                                unoptimized
                                            />
                                        </div>
                                        <div>
                                            <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                                                <h4 style={{ marginBottom: '0.1rem' }}>{winner.userId?.name}</h4>
                                                <span style={{
                                                    fontSize: '0.65rem',
                                                    fontWeight: 700,
                                                    padding: '0.1rem 0.4rem',
                                                    borderRadius: '4px',
                                                    textTransform: 'uppercase',
                                                    background: winner.status === 'approved' ? 'rgba(16,185,129,0.15)' : winner.status === 'rejected' ? 'rgba(239,68,68,0.15)' : 'rgba(245,158,11,0.15)',
                                                    color: winner.status === 'approved' ? '#10b981' : winner.status === 'rejected' ? '#ef4444' : '#f59e0b',
                                                }}>{winner.status}</span>
                                            </div>
                                            <p style={{ fontSize: '0.75rem', color: 'var(--text-muted)' }}>
                                                {winner.userId?.email}
                                            </p>
                                        </div>
                                    </div>
                                    <p style={{ fontSize: '0.875rem', color: 'var(--text-secondary)' }}>
                                        Challenge: <strong style={{ color: 'var(--text-primary)' }}>{winner.challengeId?.title || 'N/A'}</strong>
                                    </p>
                                    {winner.isWinner && (
                                        <p style={{ fontSize: '0.8rem', color: 'var(--accent-primary)', marginTop: '0.25rem', fontWeight: 600 }}>
                                            ≡ƒÅå Marked as Winner
                                        </p>
                                    )}
                                </div>

                                {/* Votes */}
                                <div style={{ textAlign: 'center', minWidth: '100px' }}>
                                    <p style={{ fontSize: '0.8rem', color: 'var(--text-muted)', marginBottom: '0.25rem' }}>
                                        Platform Votes
                                    </p>
                                    <h3 style={{ fontSize: '1.5rem', fontWeight: 700, color: 'var(--accent-primary)' }}>
                                        ≡ƒöÑ {winner.votes}
                                    </h3>
                                </div>

                                {/* Actions */}
                                <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem', minWidth: '130px' }}>
                                    <button
                                        onClick={() => toggleWinner(winner._id, winner.isWinner)}
                                        style={{
                                            padding: '0.5rem 1rem',
                                            background: winner.isWinner ? 'rgba(239, 68, 68, 0.1)' : 'var(--gradient-main)',
                                            border: winner.isWinner ? '1px solid rgba(239,68,68,0.4)' : 'none',
                                            borderRadius: '6px',
                                            color: winner.isWinner ? '#ef4444' : 'black',
                                            cursor: 'pointer',
                                            fontSize: '0.8rem',
                                            fontWeight: 600,
                                            width: '100%'
                                        }}
                                    >
                                        {winner.isWinner ? 'Γ£ò Remove Winner' : '≡ƒÅå Make Winner'}
                                    </button>
                                    {winner.status === 'pending' && (
                                        <button
                                            onClick={() => approveSubmission(winner._id)}
                                            style={{
                                                padding: '0.5rem 1rem',
                                                background: 'rgba(16, 185, 129, 0.15)',
                                                border: '1px solid rgba(16,185,129,0.3)',
                                                borderRadius: '6px',
                                                color: '#10b981',
                                                cursor: 'pointer',
                                                fontSize: '0.8rem',
                                                fontWeight: 600,
                                                width: '100%'
                                            }}
                                        >
                                            Γ£ô Approve
                                        </button>
                                    )}
                                    <button
                                        onClick={() => router.push(`/challenges/${winner.challengeId?._id}`)}
                                        style={{
                                            padding: '0.5rem 1rem',
                                            background: 'rgba(255, 255, 255, 0.05)',
                                            border: '1px solid rgba(255, 255, 255, 0.1)',
                                            borderRadius: '6px',
                                            color: 'var(--text-secondary)',
                                            cursor: 'pointer',
                                            fontSize: '0.8rem',
                                            width: '100%'
                                        }}
                                    >
                                        View Challenge
                                    </button>
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </div>
        </div>
    );
}

"use client";
import { useState, useEffect, use } from 'react';
import styles from './page.module.css';
import { toast } from 'react-hot-toast';
import { useSession } from 'next-auth/react';
import Link from 'next/link';

interface Player {
    _id: string;
    name: string;
    avatar: string;
}

interface Match {
    _id: string;
    challengeId: string;
    round: number;
    division: string;
    participants: Player[];
    scores: number[];
    winner: Player | null;
    status: 'pending' | 'active' | 'completed';
}

interface Challenge {
    _id: string;
    title: string;
    challengeType: string;
    tournamentDetails?: {
        divisions: number;
    };
    createdBy: string;
}

export default function ChallengeBracketPage({ params }: { params: Promise<{ id: string }> }) {
    const { id } = use(params);
    const { data: session } = useSession();
    const [matches, setMatches] = useState<Match[]>([]);
    const [challenge, setChallenge] = useState<Challenge | null>(null);
    const [loading, setLoading] = useState(true);
    const [activeDivision, setActiveDivision] = useState<string>('A');
    const [generating, setGenerating] = useState(false);

    useEffect(() => {
        fetchData();
    }, [id]);

    const fetchData = async () => {
        try {
            setLoading(true);
            const [challengeRes, bracketRes] = await Promise.all([
                fetch(`/api/challenges/${id}`),
                fetch(`/api/challenges/${id}/bracket`)
            ]);

            const challengeData = await challengeRes.json();
            const bracketData = await bracketRes.json();

            if (challengeData.challenge) {
                setChallenge(challengeData.challenge);
            }
            if (bracketData.matches) {
                setMatches(bracketData.matches);
            }
        } catch (error) {
            console.error('Error fetching data:', error);
            toast.error('Failed to load bracket data');
        } finally {
            setLoading(false);
        }
    };

    const generateBracket = async () => {
        try {
            setGenerating(true);
            const res = await fetch(`/api/challenges/${id}/bracket`, {
                method: 'POST',
            });
            const data = await res.json();
            if (res.ok) {
                toast.success('Bracket generated successfully!');
                fetchData();
            } else {
                toast.error(data.error || 'Failed to generate bracket');
            }
        } catch (error) {
            toast.error('An error occurred while generating the bracket');
        } finally {
            setGenerating(false);
        }
    };

    if (loading) {
        return (
            <div className={styles.loading}>
                <div className={styles.spinner}></div>
                <p>Loading tournament brackets...</p>
            </div>
        );
    }

    if (!challenge) {
        return (
            <div className={styles.empty}>
                <h2>Challenge not found</h2>
                <Link href="/challenges" className={styles.generateBtn}>Back to Challenges</Link>
            </div>
        );
    }

    const isTournament = challenge.challengeType === 'tournament';
    if (!isTournament) {
        return (
            <div className={styles.empty}>
                <h2>This is not a tournament challenge</h2>
                <Link href={`/challenges/${id}`} className={styles.generateBtn}>View Details</Link>
            </div>
        );
    }

    const divisionsCount = challenge.tournamentDetails?.divisions || 2;
    const divisionNames = ['A', 'B', 'C', 'D', 'E', 'F'].slice(0, divisionsCount);
    const isAdminOrCreator = session?.user?.role === 'admin' || session?.user?.id === challenge.createdBy;

    const filteredMatches = matches.filter(m => m.division === activeDivision);
    const rounds = Array.from(new Set(filteredMatches.map(m => m.round))).sort((a, b) => a - b);

    return (
        <div className={styles.container}>
            <div className={styles.header}>
                <Link href={`/challenges/${id}`} className="text-secondary text-sm mb-4 inline-block hover:underline">
                    ΓåÉ Back to Challenge Details
                </Link>
                <h1 className="text-gradient">{challenge.title}</h1>
                <p>Official Tournament Brackets & Match Scheduling</p>

                <div className={styles.controls}>
                    {divisionNames.map(div => (
                        <button
                            key={div}
                            onClick={() => setActiveDivision(div)}
                            className={activeDivision === div ? styles.activeTab : styles.tab}
                        >
                            Division {div}
                        </button>
                    ))}
                </div>
            </div>

            <div className={styles.divisionContainer}>
                <h2 className={styles.divisionTitle}>Division {activeDivision} Brackets</h2>

                {matches.length === 0 ? (
                    <div className={styles.empty}>
                        <p className="mb-6">Bracket has not been generated yet.</p>
                        {isAdminOrCreator && (
                            <button 
                                onClick={generateBracket} 
                                disabled={generating}
                                className={styles.generateBtn}
                            >
                                {generating ? 'Generating...' : '≡ƒ¢á∩╕Å Generate Initial Bracket'}
                            </button>
                        )}
                    </div>
                ) : (
                    <div className={styles.bracketWrapper}>
                        {rounds.map(roundNum => (
                            <div key={roundNum} className={styles.round}>
                                <h3 className={styles.roundTitle}>Round {roundNum}</h3>
                                <div className={styles.matchesColumn}>
                                    {filteredMatches
                                        .filter(m => m.round === roundNum)
                                        .map((match) => (
                                            <div key={match._id} className={styles.matchCard}>
                                                <div className={`${styles.player} ${match.winner?._id === match.participants[0]?._id ? styles.winner : ''}`}>
                                                    <div className={styles.playerInfo}>
                                                        <img src={match.participants[0]?.avatar || '/placeholder-avatar.png'} className={styles.avatar} alt="" />
                                                        <span>{match.participants[0]?.name || 'TBD'}</span>
                                                    </div>
                                                    <span className={styles.score}>{match.scores[0] || 0}</span>
                                                    {match.winner?._id === match.participants[0]?._id && <div className={styles.winnerIcon}></div>}
                                                </div>
                                                <div className={styles.divider}></div>
                                                <div className={`${styles.player} ${match.winner?._id === match.participants[1]?._id ? styles.winner : ''}`}>
                                                    <div className={styles.playerInfo}>
                                                        <img src={match.participants[1]?.avatar || '/placeholder-avatar.png'} className={styles.avatar} alt="" />
                                                        <span>{match.participants[1]?.name || 'TBD'}</span>
                                                    </div>
                                                    <span className={styles.score}>{match.scores[1] || 0}</span>
                                                    {match.winner?._id === match.participants[1]?._id && <div className={styles.winnerIcon}></div>}
                                                </div>
                                            </div>
                                        ))
                                    }
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </div>

            <div style={{ textAlign: 'center', marginTop: '3rem', color: '#666', fontSize: '0.9rem' }}>
                <p>Tournament matches follow the official platform rules.</p>
                <p>Results are validated by submission voting and verified by staff.</p>
            </div>
        </div>
    );
}

"use client";
import { useState, useEffect } from 'react';
import { useParams, useRouter } from 'next/navigation';
import Image from 'next/image';
import Link from 'next/link';
import { useSession } from 'next-auth/react';
import styles from './page.module.css';
import SubmissionModal from '@/components/challenges/SubmissionModal';
import ShareButton from '@/components/ShareButton';
import CommentSection from '@/components/challenges/CommentSection';
import JoinAgreementModal from '@/components/challenges/JoinAgreementModal';

interface Challenge {
    _id: string;
    title: string;
    description: string;
    category: string;
    participants: number;
    status: string;
    challengeType: string;
    image?: string;
    mediaUrl?: string; // New unified media format
    badge: string;
    startDate: string;
    endDate: string;
    deadlineTime: string;
    prizePool: number;
    prizeType: string;
    prizeDetails?: string;
    createdBy: { name: string };
}

interface Submission {
    _id: string;
    title: string;
    mediaUrl: string;
    votes: number;
    userId: { name: string; avatar: string };
}

export default function ChallengeDetailsPage() {
    const params = useParams();
    const router = useRouter();
    const { data: session } = useSession();
    const [challenge, setChallenge] = useState<Challenge | null>(null);
    const [submissions, setSubmissions] = useState<Submission[]>([]);
    const [loading, setLoading] = useState(true);
    const [showModal, setShowModal] = useState(false);

    // Core engagement states
    const [userVotes, setUserVotes] = useState<Set<string>>(new Set());
    const [votingInProgress, setVotingInProgress] = useState<Set<string>>(new Set());

    // New Engagement Features
    const [interested, setInterested] = useState(false);
    const [savedVideos, setSavedVideos] = useState<Set<string>>(new Set());
    const [timeLeft, setTimeLeft] = useState<string>('');
    const [boosted, setBoosted] = useState(false);

    // Sponsorship Modal
    const [showSponsorModal, setShowSponsorModal] = useState(false);
    const [sponsorForm, setSponsorForm] = useState({ amount: 100, roi: 12, creatorCut: 3 });

    // Join Flow States
    const [isJoined, setIsJoined] = useState(false);
    const [showJoinModal, setShowJoinModal] = useState(false);
    const [joining, setJoining] = useState(false);

    useEffect(() => {
        if (params.id) {
            fetchChallengeDetails(params.id as string);
            fetchSubmissions();
            if (session) {
                checkJoinStatus();
            }
        }
        if (session) {
            fetchUserVotes();
        }
    }, [params.id, session]);

    const checkJoinStatus = async () => {
        try {
            const res = await fetch(`/api/challenges/${params.id}/join`);
            const data = await res.json();
            if (res.ok) setIsJoined(data.isJoined);
        } catch (error) {
            console.error('Error checking join status:', error);
        }
    };

    // Timer Logic
    useEffect(() => {
        if (!challenge) return;
        const targetDate = challenge.deadlineTime || challenge.startDate;
        if (!targetDate) return;

        const target = new Date(targetDate).getTime();

        const updateTimer = () => {
            const now = new Date().getTime();
            const distance = target - now;

            if (distance < 0) {
                setTimeLeft("Started/Ended");
                return false; // stop interval
            }

            const days = Math.floor(distance / (1000 * 60 * 60 * 24));
            const hours = Math.floor((distance % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60));
            const minutes = Math.floor((distance % (1000 * 60 * 60)) / (1000 * 60));
            setTimeLeft(`${days > 0 ? days + 'd ' : ''}${hours}h ${minutes}m`);
            return true;
        };

        if (updateTimer()) {
            const interval = setInterval(() => {
                if (!updateTimer()) clearInterval(interval);
            }, 60000); // Update every minute
            return () => clearInterval(interval);
        }
    }, [challenge]);

    const fetchChallengeDetails = async (id: string) => {
        try {
            const res = await fetch(`/api/challenges/${id}`);
            const data = await res.json();
            if (res.ok) setChallenge(data.challenge);
        } catch (error) {
            console.error('Error fetching challenge:', error);
        } finally {
            setLoading(false);
        }
    };

    const fetchSubmissions = async () => {
        if (!params.id) return;
        try {
            const res = await fetch(`/api/submissions?challengeId=${params.id}`);
            const data = await res.json();
            if (res.ok) {
                setSubmissions(data.submissions);
            }
        } catch (error) {
            console.error('Error fetching submissions:', error);
        }
    };

    const fetchUserVotes = async () => {
        if (!session) return;
        try {
            const res = await fetch('/api/votes');
            const data = await res.json();
            if (res.ok) {
                const votedSubmissionIds = new Set<string>(
                    data.votes.map((vote: any) => (vote.submissionId?._id || vote.submissionId) as string)
                );
                setUserVotes(votedSubmissionIds);
            }
        } catch (error) {
            console.error('Error fetching user votes:', error);
        }
    };

    const handleVote = async (submissionId: string) => {
        if (!session) {
            alert('Please login to vote');
            return;
        }

        if (votingInProgress.has(submissionId)) return;

        setVotingInProgress(prev => new Set(prev).add(submissionId));

        try {
            const res = await fetch('/api/votes', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({ submissionId })
            });

            const data = await res.json();

            if (res.ok) {
                setSubmissions(prev => prev.map(sub =>
                    sub._id === submissionId
                        ? { ...sub, votes: sub.votes + (data.action === 'added' ? 1 : -1) }
                        : sub
                ));
                setUserVotes(prev => {
                    const newSet = new Set(prev);
                    if (data.action === 'added') {
                        newSet.add(submissionId);
                    } else {
                        newSet.delete(submissionId);
                    }
                    return newSet;
                });
            } else {
                alert(data.error || "Free users are limited to 1 vote per day.");
            }
        } catch (error) {
            console.error('Error voting:', error);
        } finally {
            setVotingInProgress(prev => {
                const newSet = new Set(prev);
                newSet.delete(submissionId);
                return newSet;
            });
        }
    };

    const toggleSaveVideo = (submissionId: string) => {
        if (!session) {
            alert("Login required to save videos");
            return;
        }
        setSavedVideos(prev => {
            const newSet = new Set(prev);
            if (newSet.has(submissionId)) newSet.delete(submissionId);
            else newSet.add(submissionId);
            return newSet;
        });
    };

    const handleInterestedClick = async () => {
        if (!session) {
            alert('Please login to express interest and receive notifications.');
            router.push('/auth/login');
            return;
        }

        setInterested(!interested);

        if (!interested && 'serviceWorker' in navigator && 'PushManager' in window) {
            try {
                const reg = await navigator.serviceWorker.ready;
                const sub = await reg.pushManager.subscribe({
                    userVisibleOnly: true,
                    applicationServerKey: process.env.NEXT_PUBLIC_VAPID_PUBLIC_KEY
                });
                await fetch('/api/push/subscribe', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify(sub)
                });
                console.log('Push subscription saved!');
            } catch (err) {
                console.error('Failed to subscribe for push notifications:', err);
            }
        }
    };

    const handleJoinConfirm = async () => {
        setJoining(true);
        try {
            const res = await fetch(`/api/challenges/${params.id}/join`, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    rulesAccepted: true,
                    nonRefundableAccepted: true
                })
            });

            if (res.ok) {
                setIsJoined(true);
                setShowJoinModal(false);
                setShowModal(true); // Open submission modal immediately after join
            } else {
                const data = await res.json();
                alert(data.error || 'Failed to join challenge');
            }
        } catch (error) {
            console.error('Error joining challenge:', error);
        } finally {
            setJoining(false);
        }
    };

    if (loading) return <div className="loading-screen"><div className="spinner"></div></div>;
    if (!challenge) return <div className="error-screen">Challenge not found</div>;

    const isPrize = challenge.badge === 'Prize' || challenge.prizePool > 0 || challenge.prizeType !== 'NONE';
    const mainImg = challenge.mediaUrl || challenge.image || '/images/placeholder.png';

    return (
        <div className={styles.container}>
            {showModal && (
                <SubmissionModal
                    challengeId={challenge._id}
                    onClose={() => setShowModal(false)}
                    onSuccess={() => {
                        fetchSubmissions();
                    }}
                />
            )}

            {showJoinModal && (
                <JoinAgreementModal
                    challengeTitle={challenge.title}
                    rulesPdfUrl={(challenge as any).rulesPdfUrl}
                    onConfirm={handleJoinConfirm}
                    onClose={() => setShowJoinModal(false)}
                    loading={joining}
                />
            )}

            {showSponsorModal && (
                <div style={{ position: 'fixed', top: 0, left: 0, right: 0, bottom: 0, background: 'rgba(0,0,0,0.8)', zIndex: 1000, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                    <div className="glass-card" style={{ padding: '2rem', maxWidth: '500px', width: '100%' }}>
                        <h2 className="text-gradient" style={{ marginBottom: '1rem' }}>Sponsor Challenge</h2>
                        <p style={{ color: 'var(--text-secondary)', marginBottom: '1.5rem', fontSize: '0.9rem' }}>
                            Provide prize money for this challenge. Sponsor funds require mutual approval. Default split terms apply but can be negotiated.
                        </p>

                        <div style={{ marginBottom: '1rem' }}>
                            <label style={{ display: 'block', marginBottom: '0.5rem', fontWeight: 600 }}>Funding Amount ($)</label>
                            <input
                                type="number"
                                value={sponsorForm.amount}
                                onChange={e => setSponsorForm({ ...sponsorForm, amount: Number(e.target.value) })}
                                style={{ width: '100%', padding: '0.75rem', background: 'rgba(255,255,255,0.05)', border: '1px solid var(--border-light)', borderRadius: '8px', color: 'white', outline: 'none' }}
                            />
                        </div>

                        <div style={{ display: 'flex', gap: '1rem', marginBottom: '1.5rem' }}>
                            <div style={{ flex: 1 }}>
                                <label style={{ display: 'block', marginBottom: '0.5rem', fontWeight: 600 }}>Sponsor ROI (%)</label>
                                <input
                                    type="number"
                                    value={sponsorForm.roi}
                                    onChange={e => setSponsorForm({ ...sponsorForm, roi: Number(e.target.value) })}
                                    style={{ width: '100%', padding: '0.75rem', background: 'rgba(255,255,255,0.05)', border: '1px solid var(--border-light)', borderRadius: '8px', color: 'white', outline: 'none' }}
                                />
                            </div>
                            <div style={{ flex: 1 }}>
                                <label style={{ display: 'block', marginBottom: '0.5rem', fontWeight: 600 }}>Creator Cut (%)</label>
                                <input
                                    type="number"
                                    value={sponsorForm.creatorCut}
                                    onChange={e => setSponsorForm({ ...sponsorForm, creatorCut: Number(e.target.value) })}
                                    style={{ width: '100%', padding: '0.75rem', background: 'rgba(255,255,255,0.05)', border: '1px solid var(--border-light)', borderRadius: '8px', color: 'white', outline: 'none' }}
                                />
                            </div>
                        </div>

                        <div style={{ display: 'flex', gap: '1rem', justifyContent: 'flex-end' }}>
                            <button onClick={() => setShowSponsorModal(false)} style={{ background: 'transparent', color: 'var(--text-secondary)', border: 'none', cursor: 'pointer', fontWeight: 600, padding: '0.5rem 1rem' }}>Cancel</button>
                            <button className="btn-primary" onClick={() => {
                                alert("Sponsorship proposal sent for creator approval! (Simulation)");
                                setShowSponsorModal(false);
                            }}>Send Proposal</button>
                        </div>
                    </div>
                </div>
            )}

            {/* Hero Section */}
            <div className={styles.hero}>
                <Image
                    src={mainImg.startsWith('http') ? mainImg : '/images/placeholder.png'}
                    alt={challenge.title}
                    fill
                    style={{ objectFit: 'cover' }}
                />
                <div className={`${styles.badge} ${isPrize ? styles.prizeBadge : styles.normalBadge}`}>
                    {challenge.badge} Challenge
                </div>

                {/* Save Video Action / Top Right */}
                <button
                    style={{
                        position: 'absolute', top: '1rem', right: '1rem',
                        background: 'rgba(0,0,0,0.5)', backdropFilter: 'blur(5px)',
                        border: '1px solid rgba(255,255,255,0.2)',
                        color: 'white', padding: '0.5rem 1rem', borderRadius: '12px',
                        cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '0.5rem'
                    }}
                    onClick={() => {
                        if (!session) alert("Please log in to save");
                        else alert("Challenge video added to saved list!");
                    }}
                >
                    Γ¡É Save Watch Later
                </button>
            </div>

            <div className={styles.content}>
                {/* Main Info */}
                <div className={styles.mainSection}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: '1rem' }}>
                        <h1>{challenge.title}</h1>
                        <button
                            className="btn-primary"
                            style={{
                                background: boosted ? 'linear-gradient(135deg, #10b981, #059669)' : 'var(--gradient-main)',
                                display: 'flex', alignItems: 'center', gap: '0.5rem'
                            }}
                            onClick={() => {
                                if (!session) alert("Log in to boost");
                                else setBoosted(true);
                            }}
                        >
                            ≡ƒÜÇ {boosted ? 'Boosted!' : 'Boost Challenge'}
                        </button>
                    </div>

                    <div className={styles.description}>
                        {challenge.description}
                    </div>

                    <div className={styles.statsGrid}>
                        <div className={styles.statCard}>
                            <span className={styles.statValue}>{challenge.participants}</span>
                            <span className={styles.statLabel}>Participants</span>
                        </div>
                        <div className={styles.statCard}>
                            <span className={styles.statValue}>
                                {isPrize ? (challenge.prizePool > 0
                                    ? (session?.user?.role === 'admin'
                                        ? `$${challenge.prizePool} (Admin cut: $${(challenge.prizePool * 0.15).toFixed(2)})`
                                        : `$${(challenge.prizePool * 0.85).toFixed(2)}`)
                                    : challenge.prizeDetails || 'Yes')
                                    : 'None'}
                            </span>
                            <span className={styles.statLabel}>Prize Pool {session?.user?.role !== 'admin' && challenge.prizePool > 0 && '(85% Winner)'}</span>
                        </div>
                        <div className={styles.statCard}>
                            <span className={styles.statValue}>
                                {timeLeft || challenge.status.toUpperCase()}
                            </span>
                            <span className={styles.statLabel}>Time Left / Status</span>
                        </div>
                    </div>

                    {/* Submissions Gallery */}
                    <div className={styles.submissionsSection}>
                        <h2>Community Submissions</h2>
                        <div className={styles.submissionsGrid}>
                            {submissions.map(sub => (
                                <div
                                    key={sub._id}
                                    className={styles.submissionCard}
                                    onClick={() => router.push(`/submissions/${sub._id}`)}
                                    style={{ cursor: 'pointer' }}
                                >
                                    <div className={styles.submissionImage}>
                                        <Image
                                            src={sub.mediaUrl}
                                            alt={sub.title}
                                            fill
                                            style={{ objectFit: 'cover' }}
                                        />
                                        <button
                                            onClick={(e) => {
                                                e.stopPropagation();
                                                toggleSaveVideo(sub._id);
                                            }}
                                            style={{
                                                position: 'absolute', top: '0.5rem', right: '0.5rem',
                                                background: 'rgba(0,0,0,0.6)', border: 'none', borderRadius: '50%',
                                                width: '30px', height: '30px', color: savedVideos.has(sub._id) ? 'var(--accent-primary)' : 'white',
                                                cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center'
                                            }}
                                        >
                                            {savedVideos.has(sub._id) ? 'Γÿà' : 'Γÿå'}
                                        </button>
                                    </div>
                                    <div className={styles.submissionFooter}>
                                        <div className={styles.userInfo}>
                                            <div style={{ width: 24, height: 24, borderRadius: '50%', background: '#333', overflow: 'hidden', position: 'relative' }}>
                                                <Image
                                                    src={sub.userId?.avatar || `https://ui-avatars.com/api/?name=${encodeURIComponent(sub.userId?.name || 'User')}&background=d4af37&color=000`}
                                                    alt={sub.userId?.name || 'User'}
                                                    fill
                                                    unoptimized
                                                    style={{ objectFit: 'cover' }}
                                                />
                                            </div>
                                            <span style={{ fontSize: '0.9rem' }}>{sub.userId?.name || 'Anonymous User'}</span>
                                        </div>
                                        <button
                                            onClick={(e) => {
                                                e.stopPropagation();
                                                handleVote(sub._id);
                                            }}
                                            disabled={votingInProgress.has(sub._id)}
                                            style={{
                                                background: userVotes.has(sub._id) ? 'linear-gradient(135deg, #ec4899, #f43f5e)' : 'rgba(255,255,255,0.05)',
                                                border: userVotes.has(sub._id) ? '1px solid rgba(236, 72, 153, 0.5)' : '1px solid rgba(255,255,255,0.1)',
                                                borderRadius: '12px',
                                                padding: '0.5rem 1rem',
                                                color: '#fff',
                                                cursor: votingInProgress.has(sub._id) ? 'wait' : 'pointer',
                                                display: 'flex',
                                                alignItems: 'center',
                                                gap: '0.5rem',
                                                fontSize: '0.9rem',
                                                fontWeight: '600',
                                                transition: 'all 0.2s ease',
                                                opacity: votingInProgress.has(sub._id) ? 0.6 : 1,
                                                transform: userVotes.has(sub._id) ? 'scale(1.05)' : 'scale(1)'
                                            }}
                                            onMouseEnter={(e) => {
                                                if (!votingInProgress.has(sub._id)) {
                                                    e.currentTarget.style.transform = 'scale(1.1)';
                                                    e.currentTarget.style.boxShadow = userVotes.has(sub._id)
                                                        ? '0 4px 15px rgba(236, 72, 153, 0.4)'
                                                        : '0 4px 15px rgba(255,255,255,0.1)';
                                                }
                                            }}
                                            onMouseLeave={(e) => {
                                                e.currentTarget.style.transform = userVotes.has(sub._id) ? 'scale(1.05)' : 'scale(1)';
                                                e.currentTarget.style.boxShadow = 'none';
                                            }}
                                        >
                                            <span style={{ fontSize: '1.1rem' }}>
                                                {userVotes.has(sub._id) ? 'Γ¥ñ∩╕Å' : '≡ƒñì'}
                                            </span>
                                            <span>{sub.votes}</span>
                                        </button>
                                        <Link href="/purchases/votes" style={{ fontSize: '0.75rem', color: 'var(--accent-primary)', marginTop: '0.5rem', display: 'block', textAlign: 'center' }}>
                                            Need more votes? Buy a Vote Pack
                                        </Link>
                                    </div>
                                </div>
                            ))}
                            {submissions.length === 0 && (
                                <p style={{ color: '#666' }}>No submissions yet. Be the first!</p>
                            )}
                        </div>
                    </div>

                    {/* Comments Section */}
                    <div className={styles.commentsSection}>
                        <CommentSection challengeId={challenge._id} />
                    </div>
                </div>

                {/* Sidebar Actions */}
                <div className={styles.sidebar}>
                    <div className={styles.actionCard}>
                        <h3>Ready to join?</h3>
                        <p style={{ marginBottom: '1rem', color: '#999', fontSize: '0.9rem' }}>
                            Submit your entry to participate. Or let us know you are watching!
                        </p>

                        <div style={{ display: 'flex', flexDirection: 'column', gap: '0.75rem' }}>
                            {session ? (
                                <button
                                    className={styles.joinButton}
                                    onClick={() => {
                                        if (isJoined) setShowModal(true);
                                        else setShowJoinModal(true);
                                    }}
                                >
                                    {isJoined ? 'Submit Media ≡ƒÅå' : 'Join Challenge ≡ƒÅå'}
                                </button>
                            ) : (
                                <Link href="/auth/login" style={{ width: '100%' }}>
                                    <button className={styles.joinButton} style={{ width: '100%' }}>
                                        Login to Join
                                    </button>
                                </Link>
                            )}

                            <button
                                onClick={handleInterestedClick}
                                style={{
                                    background: interested ? 'rgba(212, 175, 55, 0.1)' : 'transparent',
                                    border: '1px solid var(--accent-primary)',
                                    color: 'var(--text-primary)',
                                    padding: '0.75rem',
                                    borderRadius: '12px',
                                    fontWeight: 600,
                                    cursor: 'pointer',
                                    transition: 'all 0.2s'
                                }}
                            >
                                {interested ? '≡ƒæÇ Interested' : 'Interested in watching'}
                            </button>

                            {challenge.challengeType === 'tournament' && (
                                <Link href={`/challenges/${challenge._id}/bracket`} style={{ width: '100%' }}>
                                    <button
                                        style={{
                                            width: '100%',
                                            background: 'rgba(59, 130, 246, 0.1)',
                                            border: '1px solid #3b82f6',
                                            color: '#60a5fa',
                                            padding: '0.75rem',
                                            borderRadius: '12px',
                                            fontWeight: 600,
                                            cursor: 'pointer',
                                            transition: 'all 0.2s',
                                            display: 'flex',
                                            alignItems: 'center',
                                            justifyContent: 'center',
                                            gap: '0.5rem'
                                        }}
                                    >
                                        ≡ƒÅå View Live Bracket
                                    </button>
                                </Link>
                            )}
                        </div>
                    </div>

                    <div className={styles.actionCard} style={{ background: 'rgba(212, 175, 55, 0.05)', borderColor: 'rgba(212, 175, 55, 0.2)' }}>
                        <h3 style={{ color: 'var(--accent-primary)' }}>Sponsorship</h3>
                        <p style={{ marginBottom: '1rem', color: '#ccc', fontSize: '0.9rem' }}>
                            Fund the prize pool and earn ROI. Default 12% ROI, 3% to creator. Configurable via two-party sync.
                        </p>
                        <button
                            className="btn-primary"
                            style={{ width: '100%', background: 'var(--accent-primary)', color: 'black' }}
                            onClick={() => setShowSponsorModal(true)}
                        >
                            Propose Sponsorship
                        </button>
                    </div>

                    <div className={styles.actionCard}>
                        <h3>Share Challenge</h3>
                        <p style={{ marginBottom: '1rem', color: '#999', fontSize: '0.9rem' }}>
                            Share this challenge with your friends!
                        </p>
                        <ShareButton
                            title={challenge.title}
                            description={challenge.description}
                            url={`/challenges/${challenge._id}`}
                        />
                    </div>

                    <div className={styles.actionCard}>
                        <h3>Information & Rules</h3>
                        <ul style={{ textAlign: 'left', paddingLeft: '1.5rem', color: '#ccc', lineHeight: '1.8', fontSize: '0.9rem' }}>
                            <li>Standard Platform Policies apply.</li>
                            <li>Free users get 1 vote per challenge/day.</li>
                            <li><Link href="/purchases/votes" style={{ color: 'var(--accent-primary)' }}>Purchase additional votes here.</Link></li>
                        </ul>
                    </div>
                </div>
            </div>
        </div>
    );
}

"use client";
import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { useSession } from 'next-auth/react';
import Image from 'next/image';

export default function CreateChallengePage() {
    const router = useRouter();
    const { data: session } = useSession();
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');
    const [previewMedia, setPreviewMedia] = useState('');
    const [activeTab, setActiveTab] = useState<'public' | 'private'>('public');

    const [formData, setFormData] = useState({
        title: '',
        description: '',
        category: 'Fitness',
        customCategory: '',
        challengeType: '1v1', // 1v1, group, tournament
        teamSize: 2,
        divisions: 2, // 2, 4, 6
        scoringType: 'best_of_3', // best_of_1, best_of_3, best_of_5, best_of_7, points
        hasTimer: false,
        timerDurationMinutes: 5,
        timeLimitUploads: false,
        twoStepCompetition: false,
        startDate: '',
        endDate: '',
        deadlineTime: '',
        mediaUrl: '',
        mediaType: 'image',
        trailerUrl: '',
        rulesPdfUrl: '',
        prizeType: 'money',
        prizeDetails: '',
        locationType: 'online',
        locationDetails: '',
        entryFee: 0,
        restrictions: '',
        rulesText: '', // Will be split by newline into array
        sponsorshipRequested: false,
        sponsorRoi: 12, // Default 12%
        creatorRoi: 3,  // Default 3%
    });


    const uploadFile = async (file: File, type: 'image' | 'video' | 'raw') => {
        const formData = new FormData();
        formData.append('file', file);
        formData.append('type', type);

        const res = await fetch('/api/upload', {
            method: 'POST',
            body: formData
        });

        const data = await res.json();
        if (!res.ok) throw new Error(data.error || 'Upload failed');
        return data.url;
    };

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
        const { name, value, type } = e.target as HTMLInputElement;
        const val = type === 'number' ? Number(value) : (type === 'checkbox' ? (e.target as HTMLInputElement).checked : value);

        setFormData(prev => ({ ...prev, [name]: val }));
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();

        // ROI Validation
        if (formData.sponsorshipRequested) {
            if (formData.sponsorRoi + formData.creatorRoi !== 15) {
                setError('ROI split must total exactly 15%');
                return;
            }
        }

        setLoading(true);
        setError('');

        try {
            // Handle Media Uploads if they are Files (from state)
            let flyerUrl = formData.mediaUrl;
            let trailerUrl = formData.trailerUrl;
            let rulesPdfUrl = formData.rulesPdfUrl;

            // Note: In a real implementation, we'd store the File objects in state.
            // For now, I'll update the JSX to handle the upload immediately or on submit.
            // Let's stick to "Upload on Submit" or "Upload on Selection".
            // The current UI logic for Flyer is "Upload on Selection". Let's unify that.

            const finalData = {
                ...formData,
                isPrivate: activeTab === 'private',
                requiresSubscription: activeTab === 'private',
                rules: formData.rulesText.split('\n').filter(r => r.trim() !== ''),
                category: formData.category === 'Other' ? formData.customCategory : formData.category,
                tournamentDetails: formData.challengeType === 'tournament' ? { divisions: formData.divisions } : undefined,
                sponsorship: formData.sponsorshipRequested ? {
                    roiPercentage: formData.sponsorRoi,
                    creatorPercentage: formData.creatorRoi,
                    status: 'pending'
                } : undefined,
                timeLimitUploads: formData.timeLimitUploads,
                twoStepCompetition: formData.twoStepCompetition,
                rulesPdfUrl: formData.rulesPdfUrl
            };

            const res = await fetch('/api/challenges', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(finalData)
            });

            const data = await res.json();

            if (!res.ok) {
                throw new Error(data.error || 'Failed to create challenge');
            }

            router.push(`/challenges/${data.challenge._id}`);
        } catch (err: any) {
            console.error(err);
            setError(err.message || 'Something went wrong');
        } finally {
            setLoading(false);
        }
    };

    const inputStyles = {
        background: 'rgba(255,255,255,0.05)',
        border: '1px solid rgba(255,255,255,0.1)',
        padding: '0.75rem',
        borderRadius: '8px',
        color: 'white',
        outline: 'none',
        width: '100%',
        transition: 'border-color 0.2s',
    };

    const estimatedJackpot = formData.entryFee > 0 ? (formData.entryFee * 0.85).toFixed(2) : 0;

    return (
        <div style={{ maxWidth: '900px', margin: '0 auto', padding: '2rem' }}>
            <div className="glass-card" style={{ padding: '2.5rem', borderRadius: '16px', background: 'rgba(20, 20, 20, 0.7)' }}>
                <h1 className="text-gradient" style={{ marginBottom: '0.5rem', fontSize: '2.2rem' }}>Create New Challenge</h1>
                <p style={{ color: 'var(--text-secondary)', marginBottom: '2rem' }}>Host 1v1s, Tournaments, or Group events and manage prize pools with ease.</p>

                {error && <div style={{ background: 'rgba(239, 68, 68, 0.1)', color: '#ef4444', padding: '1rem', borderRadius: '8px', marginBottom: '1.5rem', border: '1px solid rgba(239, 68, 68, 0.2)' }}>{error}</div>}

                {/* TABS */}
                <div style={{ display: 'flex', gap: '0.5rem', marginBottom: '2.5rem', background: 'rgba(0,0,0,0.4)', padding: '0.5rem', borderRadius: '12px' }}>
                    <button
                        type="button"
                        onClick={() => setActiveTab('public')}
                        style={{
                            flex: 1, padding: '0.85rem', borderRadius: '8px', border: 'none', fontWeight: 600, cursor: 'pointer',
                            background: activeTab === 'public' ? 'linear-gradient(135deg, #f59e0b 0%, #d97706 100%)' : 'transparent',
                            color: activeTab === 'public' ? 'black' : 'var(--text-secondary)', transition: 'all 0.2s'
                        }}
                    >
                        ≡ƒîÄ Public Challenge
                    </button>
                    <button
                        type="button"
                        onClick={() => setActiveTab('private')}
                        style={{
                            flex: 1, padding: '0.85rem', borderRadius: '8px', border: 'none', fontWeight: 600, cursor: 'pointer',
                            background: activeTab === 'private' ? 'linear-gradient(135deg, #f59e0b 0%, #d97706 100%)' : 'transparent',
                            color: activeTab === 'private' ? 'black' : 'var(--text-secondary)', transition: 'all 0.2s'
                        }}
                    >
                        ≡ƒöÆ Private / Exclusive
                    </button>
                </div>

                <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '2rem' }}>

                    {/* Basic Info Section */}
                    <section style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
                        <h3 style={{ borderBottom: '1px solid rgba(255,255,255,0.1)', paddingBottom: '0.5rem', margin: 0 }}>Step 1: Challenge Details</h3>
                        <div style={{ display: 'grid', gridTemplateColumns: '2fr 1fr', gap: '1.5rem' }}>
                            <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                                <label style={{ fontWeight: 500, fontSize: '0.9rem', color: 'var(--text-secondary)' }}>Title</label>
                                <input type="text" name="title" required minLength={5} maxLength={100} value={formData.title} onChange={handleChange} placeholder="The Ultimate Showdown..." style={inputStyles} />
                            </div>
                            <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                                <label style={{ fontWeight: 500, fontSize: '0.9rem', color: 'var(--text-secondary)' }}>Category</label>
                                <select name="category" value={formData.category} onChange={handleChange} style={inputStyles}>
                                    <option value="Fitness" style={{ background: '#000' }}>Fitness</option>
                                    <option value="Creative" style={{ background: '#000' }}>Creative</option>
                                    <option value="Gaming" style={{ background: '#000' }}>Gaming</option>
                                    <option value="Learning" style={{ background: '#000' }}>Learning</option>
                                    <option value="Other" style={{ background: '#000' }}>Other</option>
                                </select>
                                {formData.category === 'Other' && (
                                    <input 
                                        type="text" 
                                        name="customCategory" 
                                        placeholder="Specify Category..." 
                                        value={formData.customCategory} 
                                        onChange={handleChange} 
                                        required 
                                        style={{ ...inputStyles, marginTop: '0.5rem' }} 
                                    />
                                )}
                            </div>

                        </div>

                        <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                            <label style={{ fontWeight: 500, fontSize: '0.9rem', color: 'var(--text-secondary)' }}>Description</label>
                            <textarea name="description" required minLength={10} maxLength={1000} value={formData.description} onChange={handleChange} rows={3} placeholder="Describe the goal of this challenge..." style={{ ...inputStyles, resize: 'vertical' }} />
                        </div>
                    </section>

                    {/* Competition Format */}
                    <section style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem', background: 'rgba(255,255,255,0.02)', padding: '1.5rem', borderRadius: '12px', border: '1px solid rgba(255,255,255,0.05)' }}>
                        <h3 style={{ borderBottom: '1px solid rgba(255,255,255,0.1)', paddingBottom: '0.5rem', margin: 0, color: '#f59e0b' }}>Step 2: Competition Format</h3>

                        <div style={{ display: 'grid', gridTemplateColumns: 'minmax(0,1fr) minmax(0,1fr)', gap: '1.5rem' }}>
                            <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                                <label style={{ fontWeight: 500, fontSize: '0.9rem', color: 'var(--text-secondary)' }}>Event Type</label>
                                <select name="challengeType" value={formData.challengeType} onChange={handleChange} style={inputStyles}>
                                    <option value="1v1" style={{ background: '#000' }}>1 vs 1 Battle</option>
                                    <option value="group" style={{ background: '#000' }}>Group Event</option>
                                    <option value="tournament" style={{ background: '#000' }}>Tournament Bracket (Max 50)</option>
                                </select>
                            </div>

                            {formData.challengeType === 'group' && (
                                <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                                    <label style={{ fontWeight: 500, fontSize: '0.9rem', color: 'var(--text-secondary)' }}>Max Team Size</label>
                                    <input type="number" name="teamSize" min={2} max={10} value={formData.teamSize} onChange={handleChange} style={inputStyles} />
                                </div>
                            )}

                            {formData.challengeType === 'tournament' && (
                                <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                                    <label style={{ fontWeight: 500, fontSize: '0.9rem', color: 'var(--text-secondary)' }}>Bracket Divisions</label>
                                    <select name="divisions" value={formData.divisions} onChange={handleChange} style={inputStyles}>
                                        <option value={2} style={{ background: '#000' }}>2 Divisions</option>
                                        <option value={4} style={{ background: '#000' }}>4 Divisions</option>
                                        <option value={6} style={{ background: '#000' }}>6 Divisions</option>
                                    </select>
                                </div>
                            )}

                            <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                                <label style={{ fontWeight: 500, fontSize: '0.9rem', color: 'var(--text-secondary)' }}>Scoring System</label>
                                <select name="scoringType" value={formData.scoringType} onChange={handleChange} style={inputStyles}>
                                    <option value="best_of_1" style={{ background: '#000' }}>1 Rounder (Tournament Only)</option>
                                    <option value="best_of_3" style={{ background: '#000' }}>Best of 3</option>
                                    <option value="best_of_5" style={{ background: '#000' }}>Best of 5</option>
                                    <option value="best_of_7" style={{ background: '#000' }}>Best of 7</option>
                                    <option value="points" style={{ background: '#000' }}>Points Based</option>
                                </select>
                            </div>
                        </div>

                        <div style={{ display: 'grid', gridTemplateColumns: 'minmax(0,1fr) minmax(0,1fr)', gap: '1.5rem' }}>
                            <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                                <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                                    <input type="checkbox" name="hasTimer" id="hasTimer" checked={formData.hasTimer} onChange={handleChange} style={{ width: '20px', height: '20px', accentColor: '#f59e0b' }} />
                                    <label htmlFor="hasTimer" style={{ fontWeight: 500, fontSize: '0.95rem' }}>Add Time Limit</label>
                                </div>
                                {formData.hasTimer && (
                                    <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem', marginLeft: '2rem' }}>
                                        <label style={{ fontWeight: 500, fontSize: '0.9rem', color: 'var(--text-secondary)' }}>Duration (Minutes)</label>
                                        <input type="number" name="timerDurationMinutes" min={1} value={formData.timerDurationMinutes} onChange={handleChange} style={inputStyles} />
                                    </div>
                                )}
                            </div>

                            <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                                <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                                    <input type="checkbox" name="timeLimitUploads" id="timeLimitUploads" checked={formData.timeLimitUploads} onChange={handleChange} style={{ width: '20px', height: '20px', accentColor: '#f59e0b' }} />
                                    <label htmlFor="timeLimitUploads" style={{ fontWeight: 500, fontSize: '0.95rem' }}>Time limit on media uploads</label>
                                </div>
                                <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                                    <input type="checkbox" name="twoStepCompetition" id="twoStepCompetition" checked={formData.twoStepCompetition} onChange={handleChange} style={{ width: '20px', height: '20px', accentColor: '#f59e0b' }} />
                                    <label htmlFor="twoStepCompetition" style={{ fontWeight: 500, fontSize: '0.95rem' }}>2-Step Competition Format</label>
                                </div>
                            </div>
                        </div>

                    </section>

                    {/* Prizes & Location */}
                    <section style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
                        <h3 style={{ borderBottom: '1px solid rgba(255,255,255,0.1)', paddingBottom: '0.5rem', margin: 0 }}>Step 3: Prizes & Logistics</h3>

                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1.5rem' }}>
                            <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                                <label style={{ fontWeight: 500, fontSize: '0.9rem', color: 'var(--text-secondary)' }}>Prize Type</label>
                                <select name="prizeType" value={formData.prizeType} onChange={handleChange} style={inputStyles}>
                                    <option value="money" style={{ background: '#000' }}>Cash Jackpot</option>
                                    <option value="digital" style={{ background: '#000' }}>Digital Prize / Coins</option>
                                    <option value="physical" style={{ background: '#000' }}>Physical Product (Appr. Req)</option>
                                    <option value="NONE" style={{ background: '#000' }}>Bragging Rights Only</option>
                                </select>
                            </div>

                            <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                                <label style={{ fontWeight: 500, fontSize: '0.9rem', color: 'var(--text-secondary)' }}>Prize Description</label>
                                <input type="text" name="prizeDetails" value={formData.prizeDetails} onChange={handleChange} placeholder={formData.prizeType === 'money' ? 'e.g., $1000 Cash' : 'e.g., PS5 Console'} style={{ ...inputStyles, opacity: formData.prizeType === 'NONE' ? 0.5 : 1 }} disabled={formData.prizeType === 'NONE'} />
                            </div>
                        </div>

                        <div style={{ display: 'grid', gridTemplateColumns: 'minmax(0,1fr) minmax(0,1fr)', gap: '1.5rem' }}>
                            <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                                <label style={{ fontWeight: 500, fontSize: '0.9rem', color: 'var(--text-secondary)' }}>Entry Fee ($)</label>
                                <input type="number" name="entryFee" min={0} value={formData.entryFee} onChange={handleChange} style={inputStyles} placeholder="0 = Free" />
                            </div>
                            <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem', justifyContent: 'center' }}>
                                <div style={{ background: 'rgba(16, 185, 129, 0.1)', border: '1px solid rgba(16, 185, 129, 0.3)', padding: '1rem', borderRadius: '8px', color: '#10b981', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                    <span style={{ fontSize: '0.9rem' }}>Projected Setup Jackpot: </span>
                                    <strong style={{ fontSize: '1.2rem' }}>${estimatedJackpot}</strong>
                                    <span style={{ fontSize: '0.7rem', opacity: 0.8, alignSelf: 'flex-end', marginLeft: '5px' }}>(85% payout)</span>
                                </div>
                            </div>
                        </div>

                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1.5rem' }}>
                            <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                                <label style={{ fontWeight: 500, fontSize: '0.9rem', color: 'var(--text-secondary)' }}>Location Format</label>
                                <select name="locationType" value={formData.locationType} onChange={handleChange} style={inputStyles}>
                                    <option value="online" style={{ background: '#000' }}>Virtual / Online</option>
                                    <option value="in-person" style={{ background: '#000' }}>In-Person Event</option>
                                </select>
                            </div>

                            {formData.locationType === 'in-person' && (
                                <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                                    <label style={{ fontWeight: 500, fontSize: '0.9rem', color: 'var(--text-secondary)' }}>Event Mapping Address</label>
                                    <input type="text" name="locationDetails" value={formData.locationDetails} onChange={handleChange} placeholder="Physical address will link to local Events..." style={inputStyles} />
                                </div>
                            )}
                        </div>

                        {/* Sponsorship Collaboration */}
                        <div style={{ background: 'rgba(59, 130, 246, 0.05)', padding: '1.5rem', borderRadius: '12px', border: '1px solid rgba(59, 130, 246, 0.2)', marginTop: '0.5rem' }}>
                            <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', marginBottom: formData.sponsorshipRequested ? '1rem' : '0' }}>
                                <input type="checkbox" name="sponsorshipRequested" id="sponsorshipRequested" checked={formData.sponsorshipRequested} onChange={handleChange} style={{ width: '20px', height: '20px', accentColor: '#3b82f6' }} />
                                <div>
                                    <label htmlFor="sponsorshipRequested" style={{ fontWeight: 600, fontSize: '1rem', color: '#60a5fa' }}>Enable Sponsorship Collaboration</label>
                                    <p style={{ margin: 0, fontSize: '0.8rem', color: 'var(--text-secondary)' }}>Allow a sponsor to fund the prize money and negotiate an ROI split.</p>
                                </div>
                            </div>

                            {formData.sponsorshipRequested && (
                                <div style={{ display: 'grid', gridTemplateColumns: 'minmax(0,1fr) minmax(0,1fr)', gap: '1rem' }}>
                                    <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                                        <label style={{ fontSize: '0.85rem', color: 'var(--text-secondary)' }}>Sponsor Return (%)</label>
                                        <input type="number" name="sponsorRoi" min={0} max={15} value={formData.sponsorRoi} onChange={handleChange} style={inputStyles} />
                                    </div>
                                    <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                                        <label style={{ fontSize: '0.85rem', color: 'var(--text-secondary)' }}>Creator Return (%)</label>
                                        <input type="number" name="creatorRoi" min={0} max={15} value={formData.creatorRoi} onChange={handleChange} style={inputStyles} />
                                    </div>
                                    <div style={{ gridColumn: '1 / -1', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                                        <span style={{ fontSize: '0.75rem', color: formData.sponsorRoi + formData.creatorRoi === 15 ? '#10b981' : '#ef4444' }}>
                                            Total Equity Sync: {formData.sponsorRoi + formData.creatorRoi}% (Must be exactly 15%)
                                        </span>
                                        {formData.sponsorRoi + formData.creatorRoi !== 15 && (
                                            <span style={{ fontSize: '0.75rem', color: '#ef4444' }}>ΓÜá∩╕Å ROI split must total 15%</span>
                                        )}
                                    </div>
                                </div>
                            )}
                        </div>


                    </section>

                    {/* Media, Dates & Rules */}
                    <section style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
                        <h3 style={{ borderBottom: '1px solid rgba(255,255,255,0.1)', paddingBottom: '0.5rem', margin: 0 }}>Step 4: Scheduling & Rules</h3>

                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: '1rem' }}>
                            <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                                <label style={{ fontWeight: 500, fontSize: '0.9rem', color: 'var(--text-secondary)' }}>Registration Deadline</label>
                                <input type="datetime-local" name="deadlineTime" required value={formData.deadlineTime} onChange={handleChange} style={{ ...inputStyles, colorScheme: 'dark' }} />
                            </div>
                            <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                                <label style={{ fontWeight: 500, fontSize: '0.9rem', color: 'var(--text-secondary)' }}>Challenge Start</label>
                                <input type="datetime-local" name="startDate" required value={formData.startDate} onChange={handleChange} style={{ ...inputStyles, colorScheme: 'dark' }} />
                            </div>
                            <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                                <label style={{ fontWeight: 500, fontSize: '0.9rem', color: 'var(--text-secondary)' }}>Challenge End</label>
                                <input type="datetime-local" name="endDate" required value={formData.endDate} onChange={handleChange} style={{ ...inputStyles, colorScheme: 'dark' }} />
                            </div>
                        </div>

                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1.5rem' }}>
                            <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                                <label style={{ fontWeight: 500, fontSize: '0.9rem', color: 'var(--text-secondary)' }}>Challenge Flyer (Image Upload)</label>
                                <div style={{ 
                                    border: '2px dashed rgba(255,255,255,0.1)', 
                                    borderRadius: '12px', 
                                    padding: '1.5rem', 
                                    textAlign: 'center',
                                    background: 'rgba(255,255,255,0.02)',
                                    cursor: 'pointer',
                                    transition: 'all 0.2s',
                                    position: 'relative'
                                }}>
                                    <input 
                                        type="file" 
                                        accept="image/*" 
                                        onChange={async (e) => {
                                            const file = e.target.files?.[0];
                                            if (file) {
                                                try {
                                                    setLoading(true);
                                                    const url = await uploadFile(file, 'image');
                                                    setFormData(prev => ({ ...prev, mediaUrl: url }));
                                                    setPreviewMedia(url);
                                                } catch (err: any) {
                                                    setError(err.message);
                                                } finally {
                                                    setLoading(false);
                                                }
                                            }
                                        }} 
                                        style={{ display: 'none' }} 
                                        id="flyer-upload"
                                    />
                                    <label htmlFor="flyer-upload" style={{ cursor: 'pointer' }}>
                                        <div style={{ fontSize: '1.5rem', marginBottom: '0.5rem' }}>≡ƒû╝∩╕Å</div>
                                        <div style={{ fontSize: '0.85rem', color: 'white' }}>Click to upload flyer</div>
                                        <div style={{ fontSize: '0.7rem', color: 'var(--text-secondary)' }}>PNG, JPG up to 5MB</div>
                                    </label>
                                </div>
                                {previewMedia && (
                                    <div style={{ marginTop: '0.5rem', position: 'relative', width: '100%', height: '120px', borderRadius: '8px', overflow: 'hidden', border: '1px solid var(--border-light)' }}>
                                        <Image src={previewMedia} alt="Preview" fill style={{ objectFit: 'cover' }} />
                                    </div>
                                )}
                            </div>
                            <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                                <label style={{ fontWeight: 500, fontSize: '0.9rem', color: 'var(--text-secondary)' }}>Challenge Trailer (Video Upload)</label>
                                <div style={{ 
                                    border: '2px dashed rgba(255,255,255,0.1)', 
                                    borderRadius: '12px', 
                                    padding: '1.5rem', 
                                    textAlign: 'center',
                                    background: 'rgba(255,255,255,0.02)',
                                    cursor: 'pointer'
                                }}>
                                    <input 
                                        type="file" 
                                        accept="video/*" 
                                        onChange={async (e) => {
                                            const file = e.target.files?.[0];
                                            if (file) {
                                                try {
                                                    setLoading(true);
                                                    const url = await uploadFile(file, 'video');
                                                    setFormData(prev => ({ ...prev, trailerUrl: url }));
                                                } catch (err: any) {
                                                    setError(err.message);
                                                } finally {
                                                    setLoading(false);
                                                }
                                            }
                                        }} 
                                        style={{ display: 'none' }} 
                                        id="trailer-upload"
                                    />
                                    <label htmlFor="trailer-upload" style={{ cursor: 'pointer' }}>
                                        <div style={{ fontSize: '1.5rem', marginBottom: '0.5rem' }}>≡ƒÄÑ</div>
                                        <div style={{ fontSize: '0.85rem', color: 'white' }}>Click to upload trailer</div>
                                        <div style={{ fontSize: '0.7rem', color: 'var(--text-secondary)' }}>MP4, MOV up to 50MB</div>
                                    </label>
                                </div>
                                {formData.trailerUrl && (
                                    <div style={{ fontSize: '0.75rem', color: '#10b981', marginTop: '0.5rem' }}>
                                        Γ£à Trailer Uploaded
                                    </div>
                                )}
                            </div>
                        </div>

                        <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                            <label style={{ fontWeight: 500, fontSize: '0.9rem', color: 'var(--text-secondary)' }}>Specific Rules (PDF Upload)</label>
                            <input 
                                type="file" 
                                accept=".pdf" 
                                onChange={async (e) => {
                                    const file = e.target.files?.[0];
                                    if (file) {
                                        try {
                                            setLoading(true);
                                            // Sending as raw for PDF
                                            const url = await uploadFile(file, 'raw' as any); 
                                            setFormData(prev => ({ ...prev, rulesPdfUrl: url }));
                                        } catch (err: any) {
                                            setError(err.message);
                                        } finally {
                                            setLoading(false);
                                        }
                                    }
                                }} 
                                style={inputStyles} 
                            />
                            {formData.rulesPdfUrl && (
                                <div style={{ fontSize: '0.75rem', color: '#10b981', marginTop: '0.2rem' }}>
                                    Γ£à Rules PDF Uploaded
                                </div>
                            )}
                            <p style={{ fontSize: '0.7rem', color: 'var(--text-secondary)', margin: 0 }}>Upload a detailed rules document for participants.</p>
                        </div>


                        <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
                            <label style={{ fontWeight: 500, fontSize: '0.9rem', color: 'var(--text-secondary)' }}>Standard Rules & Policies (One per line)</label>
                            <textarea name="rulesText" value={formData.rulesText} onChange={handleChange} rows={4} placeholder="e.g. Standard platform rules apply.&#10;No toxic behavior allowed.&#10;Late submissions will be disqualified." style={{ ...inputStyles, resize: 'vertical' }} />
                        </div>

                        {activeTab === 'private' && (
                            <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem', background: 'rgba(212, 175, 55, 0.05)', padding: '1.5rem', borderRadius: '12px', border: '1px solid var(--border-light)' }}>
                                <label style={{ fontWeight: 500, color: 'var(--accent-primary)' }}>Private Restrictions</label>
                                <input type="text" name="restrictions" value={formData.restrictions} onChange={handleChange} placeholder="e.g., Minimum 18 years old, verified users only" style={inputStyles} />
                            </div>
                        )}
                    </section>

                    <div style={{ marginTop: '1rem', display: 'flex', gap: '1rem', justifyContent: 'flex-end', borderTop: '1px solid rgba(255,255,255,0.1)', paddingTop: '1.5rem' }}>
                        <button type="button" onClick={() => router.back()} style={{ background: 'transparent', border: '1px solid var(--border-light)', color: 'var(--text-secondary)', padding: '0.75rem 1.5rem', borderRadius: '8px', cursor: 'pointer', fontWeight: 600 }}>
                            Cancel
                        </button>
                        <button type="submit" disabled={loading} style={{
                            background: 'linear-gradient(135deg, #f59e0b 0%, #d97706 100%)',
                            color: '#000',
                            border: 'none',
                            padding: '0.75rem 2rem',
                            borderRadius: '8px',
                            cursor: 'pointer',
                            fontWeight: 700,
                            opacity: loading ? 0.7 : 1,
                            transition: 'all 0.2s'
                        }}>
                            {loading ? 'Processing Event...' : 'Launch Challenge ΓåÆ'}
                        </button>
                    </div>

                </form>
            </div>
        </div>
    );
}

