                        </table>
                    )}
                </div>

                {/* Bottom Pagination */}
                <div className={styles.bottomPagination}>
                    <button
                        className={styles.navBtn}
                        onClick={() => setCurrentPage(prev => Math.max(1, prev - 1))}
