"use client";
import { useState, useEffect } from 'react';
import Image from 'next/image';
import { useSession } from 'next-auth/react';
import styles from './page.module.css';
import EditProfileModal from '@/components/profile/EditProfileModal';

interface UserData {
    _id: string;
    name: string;
    email: string;
    avatar: string;
    role: string;
    bio?: string;
    location?: string;
    website?: string;
    instagram?: string;
    tiktok?: string;
    twitter?: string;
    facebook?: string;
    whatsapp?: string;
    telegram?: string;
    stats: {
        totalPoints: number;
        badgesCollected: number;
        challengesEntered: number;
        challengesWon: number;
        followers: number;
        following: number;
        totalLikes: number;
        submissions: number;
    };
    badges?: {
        id: string;
        name: string;
        description: string;
        image: string;
        dateEarned: Date;
    }[];
}

interface Submission {
    _id: string;
    title: string;
    challengeId: { title: string; image: string };
    mediaUrl: string;
    status: string;
    votes: number;
}

export default function ProfilePage() {
    const { data: session, status } = useSession();
    const [user, setUser] = useState<UserData | null>(null);
    const [mySubmissions, setMySubmissions] = useState<Submission[]>([]);
    const [loading, setLoading] = useState(true);
    const [isEditing, setIsEditing] = useState(false);

    async function fetchProfile() {
        try {
            const res = await fetch('/api/users/me');
            if (res.ok) {
                const data = await res.json();
                setUser(data.user);
            } else {
                setUser({
                    _id: session?.user?.id || '',
                    name: session?.user?.name || 'User',
                    email: session?.user?.email || '',
                    avatar: session?.user?.avatar || '',
                    role: 'user',
                    stats: {
                        totalPoints: 0,
                        badgesCollected: 0,
                        challengesEntered: 0,
                        challengesWon: 0,
                        followers: 0,
                        following: 0,
                        totalLikes: 0,
                        submissions: 0
                    }
                });
            }
        } catch (e) {
            console.error(e);
        }
        setLoading(false);
    }

    async function fetchMySubmissions() {
        try {
            const res = await fetch(`/api/submissions?userId=${session?.user?.id}`);
            const data = await res.json();
            if (res.ok) {
                setMySubmissions(data.submissions);
            }
        } catch (error) {
            console.error(error);
        }
    }

    useEffect(() => {
        if (session?.user) {
            fetchProfile();
            fetchMySubmissions();
        } else if (status === 'unauthenticated') {
            setLoading(false);
        }
    }, [session, status]);



    // if (loading) return <div style={{ padding: '2rem' }}>Loading profile...</div>;

    if (!session && !loading) return <div style={{ padding: '2rem' }}>Please log in to view profile.</div>;

    const calculateGamificationBadges = (stats: NonNullable<UserData['stats']>) => {
        const generatedBadges = [];
        if (stats.totalPoints >= 100) {
            generatedBadges.push({
                id: 'b1',
                name: 'Emerging Voice',
                description: 'Earned 100 points in the community.',
                image: 'badge-1.png',
                dateEarned: new Date()
            });
        }
        if (stats.totalLikes >= 50) {
            generatedBadges.push({
                id: 'b2',
                name: 'Trendsetter',
                description: 'Received 50 likes on submissions.',
                image: 'badge-2.png',
                dateEarned: new Date()
            });
        }
        if (stats.challengesWon >= 1) {
            generatedBadges.push({
                id: 'b3',
                name: 'Champion',
                description: 'Won at least one challenge.',
                image: 'badge-3.png',
                dateEarned: new Date()
            });
        }
        if (stats.totalPoints >= 1000) {
            generatedBadges.push({
                id: 'b4',
                name: 'Legacy Maker',
                description: 'Achieved 1,000 community points.',
                image: 'badge-4.png',
                dateEarned: new Date()
            });
        }

        return generatedBadges;
    };

    const computedBadges = user?.stats ? calculateGamificationBadges(user.stats) : [];
    const allBadges = [...(user?.badges || []), ...computedBadges];

    const stats = [
        { label: 'Total Points', value: user?.stats?.totalPoints?.toLocaleString() || '0' },
        { label: 'Submissions', value: user?.stats?.submissions?.toString() || mySubmissions.length.toString() },
        { label: 'Total Likes', value: user?.stats?.totalLikes?.toLocaleString() || '0' },
        { label: 'Followers', value: user?.stats?.followers?.toLocaleString() || '0' },
        { label: 'Following', value: user?.stats?.following?.toLocaleString() || '0' },
    ];

    return (
        <div className={styles.profilePage}>
            {isEditing && user && (
                <EditProfileModal
                    user={user}
                    onClose={() => setIsEditing(false)}
                    onUpdate={fetchProfile}
                />
            )}

            {/* Profile Header */}
            <div className={`glass-card ${styles.profileHeader}`}>
                <div className={styles.profileInfo}>
                    <div className={styles.avatarSection}>
                        <div className={styles.avatar}>
                            {loading ? (
                                <div className="skeleton" style={{ width: 80, height: 80, borderRadius: '50%' }} />
                            ) : (
                                <div style={{ width: 80, height: 80, borderRadius: '50%', overflow: 'hidden', position: 'relative' }}>
                                    <Image
                                        key={user?.avatar || 'default'}
                                        src={user?.avatar || `https://ui-avatars.com/api/?name=${encodeURIComponent(user?.name || 'User')}&background=6366f1&color=fff`}
                                        alt="Avatar"
                                        fill
                                        unoptimized
                                        style={{ objectFit: 'cover' }}
                                    />
                                </div>
                            )}
                        </div>
                        <div className={styles.userDetails}>
                            {loading ? (
                                <>
                                    <div className="skeleton" style={{ width: '200px', height: '24px', marginBottom: '8px' }} />
                                    <div className="skeleton" style={{ width: '150px', height: '16px', marginBottom: '8px' }} />
                                    <div className="skeleton" style={{ width: '100px', height: '36px', borderRadius: '8px' }} />
                                </>
                            ) : (
                                <>
                                    <h1>{user?.name}</h1>
                                    <p className={styles.email}>≡ƒôº {user?.email}</p>

                                    {user?.bio && <p style={{ marginTop: '0.5rem', fontStyle: 'italic', opacity: 0.8 }}>{user.bio}</p>}

                                    <div style={{ display: 'flex', gap: '1rem', marginTop: '0.5rem', fontSize: '0.9rem', flexWrap: 'wrap' }}>
                                        {user?.location && <span title="Location">≡ƒôì {user.location}</span>}
                                        {user?.website && <a href={user.website} target="_blank" rel="noreferrer" style={{ color: '#a855f7' }} title="Website">≡ƒöù Website</a>}
                                    </div>

                                    {/* Social Media Links */}
                                    <div style={{ display: 'flex', gap: '1rem', marginTop: '0.75rem', flexWrap: 'wrap', alignItems: 'center' }}>
                                        {user?.instagram && (
                                            <a href={`https://instagram.com/${user.instagram.replace('@', '')}`} target="_blank" rel="noreferrer" title="Instagram" style={{ color: '#E1306C', transition: 'transform 0.2s' }} onMouseEnter={(e) => e.currentTarget.style.transform = 'scale(1.1)'} onMouseLeave={(e) => e.currentTarget.style.transform = 'scale(1)'}>
                                                <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><rect x="2" y="2" width="20" height="20" rx="5" ry="5"></rect><path d="M16 11.37A4 4 0 1 1 12.63 8 4 4 0 0 1 16 11.37z"></path><line x1="17.5" y1="6.5" x2="17.51" y2="6.5"></line></svg>
                                            </a>
