            {/* My Submissions Section */}
            <div className={styles.submissionsSection}>
                <h2>My Submissions</h2>

                {/* Submissions Grid */}
                <div className={styles.submissionsGrid}>
                    {loading ? (
                        Array.from({ length: 3 }).map((_, i) => (
