"use client";
import { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import Image from 'next/image';
import styles from './page.module.css';

interface Challenge {
    _id: string;
    title: string;
    image: string;
    status: string;
    badge: string;
}

interface Winner {
    _id: string;
    userId: {
        _id: string;
        name: string;
        avatar: string;
    };
    challengeId: Challenge;
    mediaUrl: string;
    votes: number;
    status: string;
}

export default function WinnersPage() {
    const router = useRouter();
    const [winners, setWinners] = useState<Winner[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchQuery, setSearchQuery] = useState('');
    const [filter, setFilter] = useState('all');

    useEffect(() => {
        fetchWinners();
    }, []);

    const fetchWinners = async () => {
        try {
            setLoading(true);
            // Fetch ended challenges and their top submissions
            const [challengesRes, submissionsRes] = await Promise.all([
                fetch('/api/challenges?limit=100'),
                fetch('/api/submissions?limit=100'),
            ]);

            const challengesData = await challengesRes.json();
            const submissionsData = await submissionsRes.json();

            if (challengesRes.ok && submissionsRes.ok) {
                // Get ended challenges
                const endedChallenges = challengesData.challenges.filter(
                    (c: any) => c.status === 'ended'
                );

                // For each ended challenge, find the top submission
                const winnersData: Winner[] = [];

                for (const challenge of endedChallenges) {
                    const challengeSubmissions = submissionsData.submissions
                        .filter((s: any) => s.challengeId?._id === challenge._id)
                        .sort((a: any, b: any) => b.votes - a.votes);

                    if (challengeSubmissions.length > 0) {
                        winnersData.push(challengeSubmissions[0]);
                    }
                }

                setWinners(winnersData);
            }
        } catch (error) {
            console.error('Error fetching winners:', error);
        } finally {
            setLoading(false);
        }
    };

    const filteredWinners = winners.filter(winner => {
        const matchesSearch = winner.challengeId?.title
            .toLowerCase()
            .includes(searchQuery.toLowerCase());
        return matchesSearch;
    });

    const handleViewChallenge = (challengeId: string) => {
        router.push(`/challenges/${challengeId}`);
    };

    if (loading) {
        return (
            <div className={styles.winnersPage}>
                <div style={{ padding: '2rem', textAlign: 'center' }}>
                    <div className="spinner"></div>
                    <p style={{ marginTop: '1rem', color: 'var(--text-secondary)' }}>
                        Loading winners...
                    </p>
                </div>
            </div>
        );
    }

    return (
        <div className={styles.winnersPage}>
            <header className={styles.header}>
                <div>
                    <h1 className="text-gradient">Winners</h1>
                    <p style={{ color: 'var(--text-secondary)', marginTop: '0.5rem' }}>
                        Winners of recently completed challenges
                    </p>
                </div>
            </header>

            {/* Filter */}
            <div className={styles.filterSection}>
                <button className={`${styles.filterBtn} ${styles.active}`}>
                    ≡ƒôï All Challenges Γû╝
                </button>
                <div className={styles.searchBox}>
                    <span className={styles.searchIcon}>≡ƒöì</span>
                    <input
                        type="text"
                        placeholder="Search challenges..."
                        className={styles.searchInput}
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                    />
                    <button className={styles.searchBtn}>Search</button>
                </div>
            </div>

            {/* Winners Grid */}
            <div className={styles.winnersSection}>
                <h3 className={styles.sectionTitle}>
                    Completed Challenges ({filteredWinners.length})
                </h3>

                {filteredWinners.length === 0 ? (
                    <div style={{ textAlign: 'center', padding: '3rem', color: 'var(--text-secondary)' }}>
                        <p>No completed challenges with winners yet.</p>
                        <p style={{ marginTop: '0.5rem', fontSize: '0.875rem' }}>
                            Winners will appear here once challenges end and submissions are voted on.
                        </p>
                    </div>
                ) : (
                    <div className={styles.winnersGrid}>
                        {filteredWinners.map((winner) => (
                            <div key={winner._id} className={`glass-card ${styles.winnerCard}`}>
                                <div className={styles.winnerImage}>
                                    <Image
                                        src={winner.mediaUrl || winner.challengeId?.image || '/images/placeholder.png'}
                                        alt={winner.challengeId?.title || 'Challenge'}
                                        fill
                                        unoptimized
                                        style={{ objectFit: 'cover' }}
                                    />
                                    {winner.challengeId?.badge === 'Prize' && (
                                        <div style={{
                                            position: 'absolute',
                                            top: '0.5rem',
                                            right: '0.5rem',
                                            background: 'linear-gradient(135deg, #FFD700, #FFA500)',
                                            padding: '0.25rem 0.75rem',
                                            borderRadius: '4px',
                                            fontSize: '0.75rem',
                                            fontWeight: 600,
                                        }}>
                                            ≡ƒÅå PRIZE
                                        </div>
                                    )}
                                </div>

                                <div className={styles.winnerContent}>
                                    <h4>{winner.challengeId?.title || 'Challenge'}</h4>

                                    <div className={styles.winnerInfo}>
                                        <div style={{
                                            width: '24px',
                                            height: '24px',
                                            borderRadius: '50%',
                                            overflow: 'hidden',
                                            position: 'relative',
                                        }}>
                                            <Image
                                                src={winner.userId?.avatar || `https://ui-avatars.com/api/?name=${winner.userId?.name || 'User'}`}
                                                alt={winner.userId?.name || 'User'}
                                                fill
                                                unoptimized
                                                style={{ objectFit: 'cover' }}
                                            />
                                        </div>
                                        <span className={styles.winnerName}>
                                            {winner.userId?.name || 'Unknown User'}
                                        </span>
                                    </div>

                                    <div className={styles.metricInfo}>
                                        <span className={styles.metricIcon}>Γ¥ñ∩╕Å</span>
                                        <span className={styles.metric}>
                                            {winner.votes.toLocaleString()} Votes
                                        </span>
                                    </div>

                                    <button
                                        className={styles.viewBtn}
                                        onClick={() => handleViewChallenge(winner.challengeId._id)}
                                    >
                                        View
                                    </button>
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </div>
        </div>
    );
}

import { NextRequest, NextResponse } from 'next/server';
export const dynamic = 'force-dynamic';
import { getServerSession } from 'next-auth';
import connectDB from '@/lib/db/mongodb';
import { authOptions } from '@/lib/auth/authOptions';
import mongoose from 'mongoose';

// Ensure connection before using mongoose.connection
async function ensureConnection() {
    await connectDB();
}

// Helper to check admin
async function checkAdmin() {
    const session = await getServerSession(authOptions);
    if (!session || session.user.role !== 'admin') {
        throw new Error('Unauthorized');
    }
}

export async function GET(request: NextRequest) {
    try {
        await checkAdmin();
        const conn = await connectDB();
        const db = conn.connection.db;

        if (!db) throw new Error('Database not connected');

        const { searchParams } = new URL(request.url);
        const collectionName = searchParams.get('collection');
        const countOnly = searchParams.get('count');

        // 1. List Collections
        if (!collectionName) {
            const collections = await db.listCollections().toArray();
            const stats = await Promise.all(collections.map(async (c: any) => {
                const count = await db.collection(c.name).countDocuments();
                return { name: c.name, count };
            }));

            return NextResponse.json({ collections: stats });
        }

        // 2. List Documents provided a collection
        const collection = db.collection(collectionName);

        if (countOnly) {
            const count = await collection.countDocuments();
            return NextResponse.json({ count });
        }

        const limit = parseInt(searchParams.get('limit') || '50');
        const page = parseInt(searchParams.get('page') || '1');
        const skip = (page - 1) * limit;

        const documents = await collection.find({})
            .skip(skip)
            .limit(limit)
            .toArray();

        // Convert ObjectId to string for JSON serialization
        // const safeDocs = JSON.parse(JSON.stringify(documents));

        return NextResponse.json({
            documents,
            page,
            limit
        });

    } catch (error: any) {
        return NextResponse.json(
            { error: error.message || 'Database error' },
            { status: error.message === 'Unauthorized' ? 401 : 500 }
        );
    }
}

export async function PUT(request: NextRequest) {
    try {
        await checkAdmin();
        const body = await request.json();
        const { collection: collectionName, id, data } = body;

        if (!collectionName || !id || !data) {
            return NextResponse.json({ error: 'Missing parameters' }, { status: 400 });
        }

        const conn = await connectDB();
        const db = conn.connection.db;

        if (!db) throw new Error('Database not connected');
        const collection = db.collection(collectionName);

        // Try to create an ObjectId, otherwise assume string ID
        let queryId;
        try {
            queryId = new mongoose.Types.ObjectId(id);
        } catch (e) {
            queryId = id;
        }

        // Removing _id from data to prevent immutable field error
        const { _id, ...updateData } = data;

        const result = await collection.updateOne(
            { _id: queryId } as any,
            { $set: updateData }
        );

        return NextResponse.json({ success: true, result });

    } catch (error: any) {
        return NextResponse.json(
            { error: error.message || 'Update failed' },
            { status: 500 }
        );
    }
}

export async function DELETE(request: NextRequest) {
    try {
        await checkAdmin();
        const { searchParams } = new URL(request.url);
        const collectionName = searchParams.get('collection');
        const id = searchParams.get('id');

        if (!collectionName || !id) {
            return NextResponse.json({ error: 'Missing parameters' }, { status: 400 });
        }

        const conn = await connectDB();
        const db = conn.connection.db;

        if (!db) throw new Error('Database not connected');
        const collection = db.collection(collectionName);

        let queryId;
        try {
            queryId = new mongoose.Types.ObjectId(id);
        } catch (e) {
            queryId = id;
        }

        const result = await collection.deleteOne({ _id: queryId } as any);

        return NextResponse.json({ success: true, result });
    } catch (error: any) {
        return NextResponse.json(
            { error: error.message || 'Delete failed' },
            { status: 500 }
        );
    }
}

import { NextRequest, NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import connectDB from '@/lib/db/mongodb';
import User from '@/lib/db/models/User';
import Challenge from '@/lib/db/models/Challenge';
import Submission from '@/lib/db/models/Submission';
import { authOptions } from '@/lib/auth/authOptions';

export async function GET(request: NextRequest) {
    try {
        const session = await getServerSession(authOptions);


        if (!session || session.user.role !== 'admin') {
            return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
        }

        await connectDB();

        const [totalChallenges, totalUsers, totalSubmissions] = await Promise.all([
            Challenge.countDocuments(),
            User.countDocuments(),
            Submission.countDocuments(),
        ]);

        // Get active challenges count
        const activeChallenges = await Challenge.countDocuments({ status: 'active' });

        // Get recent challenges (last 5)
        const recentChallenges = await Challenge.find()
            .sort({ createdAt: -1 })
            .limit(5)
            .populate('createdBy', 'name')
            .select('title status participants startDate endDate')
            .lean();


        const topLeaders = await User.find()
            .sort({ 'stats.totalPoints': -1 })
            .limit(3)
            .select('name stats.totalPoints stats.challengesWon')
            .lean();

        // Get recent submissions for activity feed
        const recentSubmissions = await Submission.find()
            .sort({ createdAt: -1 })
            .limit(5)
            .populate('userId', 'name')
            .populate('challengeId', 'title')
            .select('userId challengeId status createdAt')
            .lean();

        // Calculate trends (simplified - comparing with last week)
        const oneWeekAgo = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000);
        const [newChallengesThisWeek, newUsersThisWeek, newSubmissionsThisWeek] = await Promise.all([
            Challenge.countDocuments({ createdAt: { $gte: oneWeekAgo } }),
            User.countDocuments({ createdAt: { $gte: oneWeekAgo } }),
            Submission.countDocuments({ createdAt: { $gte: oneWeekAgo } }),
        ]);

        return NextResponse.json({
            stats: {
                totalChallenges,
                totalUsers,
                totalSubmissions,
                activeChallenges,
                trends: {
                    challenges: newChallengesThisWeek,
                    users: newUsersThisWeek,
                    submissions: newSubmissionsThisWeek,
                }
            },
            recentChallenges: recentChallenges.map(c => ({
                id: c._id.toString(),
                name: c.title,
                status: c.status,
                participants: c.participants || 0,
                duration: calculateDuration(c.startDate, c.endDate),
            })),
            topLeaders: topLeaders.map((user, idx) => ({
                rank: idx + 1,
                name: user.name,
                points: user.stats?.totalPoints || 0,
                challenges: user.stats?.challengesWon || 0,
            })),
            recentActivity: recentSubmissions.map(sub => ({
                user: (sub.userId as any)?.name || 'Unknown',
                action: `submitted to ${(sub.challengeId as any)?.title || 'a challenge'}`,
                time: getRelativeTime(sub.createdAt),
            })),
        });

    } catch (error: any) {
        console.error('Admin stats error:', error);
        return NextResponse.json(
            { error: error.message || 'Failed to fetch admin stats' },
            { status: 500 }
        );
    }
}

function calculateDuration(start: Date, end: Date): string {
    const days = Math.ceil((new Date(end).getTime() - new Date(start).getTime()) / (1000 * 60 * 60 * 24));
    return `${days} days`;
}

function getRelativeTime(date: Date): string {
    const seconds = Math.floor((Date.now() - new Date(date).getTime()) / 1000);

    if (seconds < 60) return 'just now';
    if (seconds < 3600) return `${Math.floor(seconds / 60)}m ago`;
    if (seconds < 86400) return `${Math.floor(seconds / 3600)}h ago`;
    return `${Math.floor(seconds / 86400)}d ago`;
}

