            });
        }

        return NextResponse.json({
            success: true,
            message: `Submission marked as ${isWinner ? 'winner' : 'not a winner'}`
        });
    } catch (error: any) {
        console.error('Admin winner selection error:', error);
        return NextResponse.json(
            { error: error.message || 'Failed to update winner status' },
            { status: 500 }
        );
