import { NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/lib/auth/authOptions';
import dbConnect from '@/lib/db/mongodb';
import PushSubscription from '@/lib/db/models/PushSubscription';
import webpush, { sendPushNotification } from '@/lib/push';

export async function POST(req: Request) {
    try {
        const session = await getServerSession(authOptions);
        if (!session) {
            return NextResponse.json({ message: 'Unauthorized' }, { status: 401 });
        }

        const { title, body, url } = await req.json();

        if (!title || !body) {
            return NextResponse.json({ message: 'Missing fields' }, { status: 400 });
        }

        await dbConnect();

        const subscriptions = await PushSubscription.find({ userId: session.user.id });

        const payload = JSON.stringify({
            title,
            body,
            url: url || '/feed',
            icon: '/icon-192x192.png',
        });

        const promises = subscriptions.map(sub =>
            webpush.sendNotification({
                endpoint: sub.endpoint,
                keys: sub.keys
            }, payload)
                .catch(err => {
                    if (err.statusCode === 410 || err.statusCode === 404) {
                        // Start async cleanup...
                        PushSubscription.deleteOne({ _id: sub._id }).exec();
                    }
                    console.error('Push error:', err);
                    return null;
                })
        );

        await Promise.all(promises);

        return NextResponse.json({ message: 'Sent notification(s)' }, { status: 200 });
    } catch (error) {
        console.error('Error sending push:', error);
        return NextResponse.json({ message: 'Failed to send' }, { status: 500 });
    }
}

import { NextRequest, NextResponse } from 'next/server';
import connectDB from '@/lib/db/mongodb';
import User from '@/lib/db/models/User';
import Submission from '@/lib/db/models/Submission';
import Follow from '@/lib/db/models/Follow';
import Leaderboard from '@/lib/db/models/Leaderboard';
import { checkAndAwardBadges } from '@/lib/badges';

export async function GET() {
    try {
        await connectDB();

        const users = await User.find({});
        const results = [];

        for (const user of users) {
            // Count actual submissions
            const submissionCount = await Submission.countDocuments({ userId: user._id });
            const totalLikesRes = await Submission.aggregate([
                { $match: { userId: user._id } },
                { $group: { _id: null, totalLikes: { $sum: '$votes' } } }
            ]);
            const totalLikes = totalLikesRes[0]?.totalLikes || 0;

            // Update stats
            const totalPoints = (submissionCount * 50) + (totalLikes * 10);
            user.stats.challengesEntered = submissionCount;
            user.stats.totalPoints = totalPoints;

            // Update Global Leaderboard
            await Leaderboard.findOneAndUpdate(
                { userId: user._id, challengeId: null },
                { points: totalPoints },
                { upsert: true }
            );

            // Fix missing username
            if (!user.username) {
                user.username = user.email.split('@')[0].toLowerCase().replace(/[^a-z0-9]/g, '');
                // Ensure uniqueness (simple version)
                const existing = await User.findOne({ username: user.username, _id: { $ne: user._id } });
                if (existing) {
                    user.username = user.username + Math.floor(Math.random() * 1000);
                }
            }

            await user.save();

            // Re-check badges
            await checkAndAwardBadges(user._id.toString());

            results.push({
                email: user.email,
                username: user.username,
                stats: user.stats,
                badgesAwarded: user.badges.length
            });
        }

        return NextResponse.json({
            message: 'Repair completed',
            results
        });
    } catch (error: any) {
        return NextResponse.json({ error: error.message }, { status: 500 });
    }
}

import { NextRequest, NextResponse } from 'next/server';
import connectDB from '@/lib/db/mongodb';
import Submission from '@/lib/db/models/Submission';
import Challenge from '@/lib/db/models/Challenge';
import User from '@/lib/db/models/User';

// GET /api/search?q=query&type=all|submissions|challenges|users
export async function GET(request: NextRequest) {
    try {
        await connectDB();

        const { searchParams } = new URL(request.url);
        const query = searchParams.get('q') || '';
        const type = searchParams.get('type') || 'all';
        const limit = parseInt(searchParams.get('limit') || '20');

        if (!query || query.length < 2) {
            return NextResponse.json(
                { error: 'Search query must be at least 2 characters' },
                { status: 400 }
            );
        }

        const results: any = {};

        // Search Submissions
        if (type === 'all' || type === 'submissions') {
            const submissions = await Submission.find({
                $or: [
                    { title: { $regex: query, $options: 'i' } },
                    { description: { $regex: query, $options: 'i' } },
                ],
                status: 'approved',
            })
                .populate('userId', 'name avatar')
                .populate('challengeId', 'title category')
                .sort({ votes: -1, createdAt: -1 })
                .limit(limit)
                .lean();

            results.submissions = submissions;
        }

        // Search Challenges
        if (type === 'all' || type === 'challenges') {
            const challenges = await Challenge.find({
                $or: [
                    { title: { $regex: query, $options: 'i' } },
                    { description: { $regex: query, $options: 'i' } },
                    { category: { $regex: query, $options: 'i' } },
                ],
            })
                .sort({ participants: -1, createdAt: -1 })
                .limit(limit)
                .lean();

            results.challenges = challenges;
        }

        // Search Users
        if (type === 'all' || type === 'users') {
            const users = await User.find({
                $or: [
                    { name: { $regex: query, $options: 'i' } },
                    { email: { $regex: query, $options: 'i' } },
                ],
            })
                .select('name email avatar points role')
                .sort({ points: -1 })
                .limit(limit)
                .lean();

            results.users = users;
        }

        return NextResponse.json({
            query,
            results,
            count: {
                submissions: results.submissions?.length || 0,
                challenges: results.challenges?.length || 0,
                users: results.users?.length || 0,
            },
        });
    } catch (error: any) {
        console.error('Search error:', error);
        return NextResponse.json(
            { error: error.message || 'Search failed' },
            { status: 500 }
        );
    }
}

