import { NextRequest, NextResponse } from 'next/server';
import connectDB from '@/lib/db/mongodb';
import Submission from '@/lib/db/models/Submission';

// GET /api/trending?period=day|week|month&limit=10
export async function GET(request: NextRequest) {
    try {
        await connectDB();

        const { searchParams } = new URL(request.url);
        const period = searchParams.get('period') || 'week';
        const limit = parseInt(searchParams.get('limit') || '10');

        // Calculate date range
        const now = new Date();
        let startDate = new Date();

        switch (period) {
            case 'day':
                startDate.setDate(now.getDate() - 1);
                break;
            case 'week':
                startDate.setDate(now.getDate() - 7);
                break;
            case 'month':
                startDate.setMonth(now.getMonth() - 1);
                break;
            default:
                startDate.setDate(now.getDate() - 7);
        }

        // Get trending submissions (most votes in time period)
        const trending = await Submission.find({
            createdAt: { $gte: startDate },
            status: 'approved',
        })
            .populate('userId', 'name avatar')
            .populate('challengeId', 'title category')
            .sort({ votes: -1, createdAt: -1 })
            .limit(limit)
            .lean();

        return NextResponse.json({
            period,
            trending,
            count: trending.length,
        });
    } catch (error: any) {
        console.error('Trending error:', error);
        return NextResponse.json(
            { error: error.message || 'Failed to fetch trending' },
            { status: 500 }
        );
    }
}

import { NextRequest, NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import { authOptions } from '@/lib/auth/authOptions';
import { uploadToCloudinary } from '@/lib/utils/cloudinary';

// POST /api/upload - Upload file to Cloudinary
export async function POST(request: NextRequest) {
    try {
        const session = await getServerSession(authOptions);
        if (!session) {
            return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
        }

        const formData = await request.formData();
        const file = formData.get('file') as File;
        const type = formData.get('type') as string; // 'image' or 'video'

        if (!file) {
            return NextResponse.json(
                { error: 'No file provided' },
                { status: 400 }
            );
        }

        // Validate file type
        const resourceType = type === 'video' ? 'video' : 'image';
        const allowedTypes = resourceType === 'image'
            ? ['image/jpeg', 'image/png', 'image/webp', 'image/gif']
            : ['video/mp4', 'video/webm', 'video/quicktime'];

        if (!allowedTypes.includes(file.type)) {
            return NextResponse.json(
                { error: `Invalid file type. Allowed: ${allowedTypes.join(', ')}` },
                { status: 400 }
            );
        }

        // Validate file size (10MB for images, 50MB for videos)
        const maxSize = resourceType === 'image' ? 10 * 1024 * 1024 : 50 * 1024 * 1024;
        if (file.size > maxSize) {
            return NextResponse.json(
                { error: `File too large. Max size: ${maxSize / (1024 * 1024)}MB` },
                { status: 400 }
            );
        }

        // Convert file to base64
        const bytes = await file.arrayBuffer();
        const buffer = Buffer.from(bytes);
        const base64 = `data:${file.type};base64,${buffer.toString('base64')}`;

        // Upload to Cloudinary
        const result = await uploadToCloudinary(
            base64,
            'challenge-suite',
            resourceType
        );

        return NextResponse.json({
            message: 'File uploaded successfully',
            url: result.url,
            publicId: result.publicId,
            width: result.width,
            height: result.height,
            format: result.format,
        });
    } catch (error: any) {
        console.error('Upload error:', error);
        return NextResponse.json(
            { error: error.message || 'Failed to upload file' },
            { status: 500 }
        );
    }
}

