        description: 'Maintained a 7-day streak',
        image: 'streak-keeper.png',
    },
    CREATIVE_GENIUS: {
        id: 'creative-genius',
        name: 'Creative Genius',
        description: 'Received 100 votes on a submission',
        image: 'creative-genius.png',
    },
    COMMUNITY_HERO: {
